     1→import { invoke } from "@tauri-apps/api/core";
     2→import { listen } from "@tauri-apps/api/event";
     3→import { InputRule } from "@tiptap/core";
     4→import CodeBlockLowlight from "@tiptap/extension-code-block-lowlight";
     5→import Image from "@tiptap/extension-image";
     6→import Link from "@tiptap/extension-link";
     7→import { Mathematics } from "@tiptap/extension-mathematics";
     8→import Placeholder from "@tiptap/extension-placeholder";
     9→import { Table } from "@tiptap/extension-table";
    10→import { TableCell } from "@tiptap/extension-table-cell";
    11→import { TableHeader } from "@tiptap/extension-table-header";
    12→import { TableRow } from "@tiptap/extension-table-row";
    13→import Typography from "@tiptap/extension-typography";
    14→import { EditorContent, ReactNodeViewRenderer, useEditor } from "@tiptap/react";
    15→import StarterKit from "@tiptap/starter-kit";
    16→import { common, createLowlight } from "lowlight";
    17→import { useEffect, useRef, useState } from "react";
    18→import { Markdown } from "tiptap-markdown";
    19→import { FindReplace } from "../lib/tiptap/FindReplace";
    20→import { InlineEditMode } from "../lib/tiptap/InlineEditMode";
    21→import { LinkPreview } from "../lib/tiptap/LinkPreview";
    22→import { TextFolding } from "../lib/tiptap/TextFolding";
    23→import { BubbleMenu } from "./BubbleMenu";
    24→import { CodeBlockView } from "./CodeBlockView";
    25→import { FindReplaceBar } from "./FindReplaceBar";
    26→import { LinkDialog } from "./LinkDialog";
    27→import { TableControls } from "./TableControls";
    28→import "katex/dist/katex.min.css";
    29→import "../styles/editor.css";
    30→
    31→const lowlight = createLowlight(common);
    32→
    33→const IMAGE_MIME = /^image\/(png|jpe?g|gif|webp|avif|svg\+xml)$/;
    34→
    35→interface EditorProps {
    36→  content?: string;
    37→  filePath?: string;
    38→  typewriterMode?: boolean;
    39→  spellCheck?: boolean;
    40→  onWordCount?: (count: number) => void;
    41→  onChange?: (markdown: string) => void;
    42→}
    43→
    44→export function Editor({
    45→  content = "",
    46→  filePath,
    47→  typewriterMode = false,
    48→  spellCheck = true,
    49→  onWordCount,
    50→  onChange,
    51→}: EditorProps) {
    52→  const scrollRef = useRef<HTMLDivElement>(null);
    53→  const typewriterRef = useRef(typewriterMode);
    54→  useEffect(() => {
    55→    typewriterRef.current = typewriterMode;
    56→  }, [typewriterMode]);
    57→
    58→  const [linkDialog, setLinkDialog] = useState<{ href: string } | null>(null);
    59→  const [showFindReplace, setShowFindReplace] = useState(false);
    60→
    61→  const editor = useEditor({
    62→    extensions: [
    63→      StarterKit.configure({ codeBlock: false }),
    64→      CodeBlockLowlight.extend({
    65→        addNodeView() {
    66→          return ReactNodeViewRenderer(CodeBlockView);
    67→        },
    68→      }).configure({ lowlight }),
    69→      Markdown.configure({
    70→        transformPastedText: true,
    71→        transformCopiedText: true,
    72→      }),
    73→      Placeholder.configure({
    74→        placeholder: "Start writing…",
    75→      }),
    76→      Typography,
    77→      Link.extend({
    78→        addInputRules() {
    79→          return [
    80→            new InputRule({
    81→              // Match completed [text](url) at the cursor
    82→              find: /\[([^[\]]+)\]\(([^()]+)\)$/,
    83→              handler: ({ range, match, chain }) => {
    84→                const [, text, href] = match;
    85→                chain()
    86→                  .deleteRange(range)
    87→                  .insertContentAt(range.from, {
    88→                    type: "text",
    89→                    text,
    90→                    marks: [{ type: "link", attrs: { href, rel: "noopener noreferrer" } }],
    91→                  })
    92→                  .run();
    93→              },
    94→            }),
    95→          ];
    96→        },
    97→      }).configure({
    98→        openOnClick: false,
    99→        HTMLAttributes: { rel: "noopener noreferrer" },
   100→      }),
   101→      Image,
   102→      Table.configure({ resizable: true }),
   103→      TableRow,
   104→      TableHeader,
   105→      TableCell,
   106→      Mathematics,
   107→      LinkPreview,
   108→      FindReplace,
   109→      TextFolding,
   110→      InlineEditMode,
   111→    ],
   112→    content,
   113→    editorProps: {
   114→      attributes: { spellcheck: spellCheck ? "true" : "false" },
   115→      handlePaste(view, event) {
   116→        const text = (event.clipboardData?.getData("text/plain") ?? "").trim();
   117→        if (!/^https?:\/\/\S+$/.test(text)) return false;
   118→        if (view.state.selection.empty) return false;
   119→        // Paste a URL with text selected → apply it as a link mark
   120→        event.preventDefault();
   121→        const { from, to } = view.state.selection;
   122→        const linkMark = view.state.schema.marks.link.create({
   123→          href: text,
   124→          rel: "noopener noreferrer",
   125→        });
   126→        view.dispatch(view.state.tr.addMark(from, to, linkMark));
   127→        return true;
   128→      },
   129→      handleDrop(view, event) {
   130→        const imageFiles = Array.from(event.dataTransfer?.files ?? [])
   131→          .filter((f) => IMAGE_MIME.test(f.type))
   132→          .map((f) => ({ name: f.name, srcPath: (f as { path?: string }).path }))
   133→          .filter((f): f is { name: string; srcPath: string } => f.srcPath !== undefined);
   134→        if (imageFiles.length === 0) return false;
   135→        event.preventDefault();
   136→        // Capture coords now; recompute position after async uploads settle
   137→        // to avoid using a stale absolute offset if the document changes.
   138→        const dropX = event.clientX;
   139→        const dropY = event.clientY;
   140→        Promise.allSettled(
   141→          imageFiles.map(({ name, srcPath }) =>
   142→            invoke<string>("save_asset", { srcPath, activeFilePath: filePath }).then((relPath) => ({
   143→              name,
   144→              relPath,
   145→            }))
   146→          )
   147→        ).then((results) => {
   148→          const saved = results.flatMap((r) => {
   149→            if (r.status === "fulfilled") return [r.value];
   150→            console.error("save_asset failed:", r.reason);
   151→            return [];
   152→          });
   153→          if (saved.length === 0) return;
   154→          const dropPos = view.posAtCoords({ left: dropX, top: dropY })?.pos;
   155→          if (dropPos === undefined) return;
   156→          // Apply all insertions in one transaction to avoid stale positions
   157→          const tr = view.state.tr;
   158→          let offset = 0;
   159→          for (const { name, relPath } of saved) {
   160→            const node = view.state.schema.nodes.image.create({ src: relPath, alt: name });
   161→            tr.insert(dropPos + offset, node);
   162→            offset += node.nodeSize;
   163→          }
   164→          view.dispatch(tr);
   165→        });
   166→        return true;
   167→      },
   168→    },
   169→    onUpdate({ editor }) {
   170→      // biome-ignore lint/suspicious/noExplicitAny: tiptap-markdown storage has no public type
   171→      const markdown = (editor.storage as any).markdown.getMarkdown() as string;
   172→      onChange?.(markdown);
   173→
   174→      if (onWordCount) {
   175→        const text = editor.getText();
   176→        onWordCount(text.trim() ? text.trim().split(/\s+/).length : 0);
   177→      }
   178→    },
   179→    onSelectionUpdate({ editor: ed }) {
   180→      if (!typewriterRef.current || !scrollRef.current) return;
   181→      const { from } = ed.view.state.selection;
   182→      const coords = ed.view.coordsAtPos(from);
   183→      if (coords.top === 0 && coords.bottom === 0) return;
   184→      const scrollEl = scrollRef.current;
   185→      const rect = scrollEl.getBoundingClientRect();
   186→      const cursorRelTop = coords.top - rect.top;
   187→      const target = scrollEl.scrollTop + cursorRelTop - rect.height / 2;
   188→      scrollEl.scrollTo({ top: Math.max(0, target), behavior: "smooth" });
   189→    },
   190→  });
   191→
   192→  // Update spellcheck live — set directly on the DOM to avoid replacing editorProps
   193→  useEffect(() => {
   194→    if (!editor) return;
   195→    try {
   196→      editor.view.dom.setAttribute("spellcheck", spellCheck ? "true" : "false");
   197→    } catch {
   198→      // view not yet mounted — initial value is set via editorProps in useEditor
   199→    }
   200→  }, [editor, spellCheck]);
   201→
   202→  // Click on the ](url) hint from InlineEditMode → open link dialog
   203→  // Use scrollRef instead of editor.view.dom to avoid accessing the view before it's mounted
   204→  useEffect(() => {
   205→    const container = scrollRef.current;
   206→    if (!container || !editor) return;
   207→    function onMouseDown(e: MouseEvent) {
   208→      const target = e.target as HTMLElement;
   209→      if (!target.classList.contains("link-url-hint")) return;
   210→      e.preventDefault();
   211→      const href = editor.getAttributes("link").href ?? "";
   212→      setLinkDialog({ href });
   213→    }
   214→    container.addEventListener("mousedown", onMouseDown);
   215→    return () => container.removeEventListener("mousedown", onMouseDown);
   216→  }, [editor]);
   217→
   218→  // Cmd+K — open link dialog when editor is focused
   219→  useEffect(() => {
   220→    function onKeyDown(e: KeyboardEvent) {
   221→      if (!(e.metaKey || e.ctrlKey) || e.key?.toLowerCase() !== "k") return;
   222→      if (!editor?.isFocused) return;
   223→      e.preventDefault();
   224→      const href = editor.getAttributes("link").href ?? "";
   225→      setLinkDialog({ href });
   226→    }
   227→    window.addEventListener("keydown", onKeyDown);
   228→    return () => window.removeEventListener("keydown", onKeyDown);
   229→  }, [editor]);
   230→
   231→  // Cmd+E — toggle inline code; intercept before WKWebView's "Use Selection for Find"
   232→  useEffect(() => {
   233→    function onKeyDown(e: KeyboardEvent) {
   234→      if (!(e.metaKey || e.ctrlKey) || e.key?.toLowerCase() !== "e") return;
   235→      if (!editor?.isFocused) return;
   236→      e.preventDefault();
   237→      editor.chain().focus().toggleCode().run();
   238→    }
   239→    window.addEventListener("keydown", onKeyDown);
   240→    return () => window.removeEventListener("keydown", onKeyDown);
   241→  }, [editor]);
   242→
   243→  // Cmd+Shift+V — paste as plain text, stripping all rich formatting
   244→  useEffect(() => {
   245→    function onKeyDown(e: KeyboardEvent) {
   246→      if (!(e.metaKey || e.ctrlKey) || !e.shiftKey || e.key?.toLowerCase() !== "v") return;
   247→      if (!editor?.isFocused) return;
   248→      e.preventDefault();
   249→      navigator.clipboard
   250→        .readText()
   251→        .then((text) => {
   252→          editor.view.dispatch(editor.view.state.tr.insertText(text));
   253→        })
   254→        .catch((err) => {
   255→          console.error("Failed to read clipboard:", err);
   256→        });
   257→    }
   258→    window.addEventListener("keydown", onKeyDown);
   259→    return () => window.removeEventListener("keydown", onKeyDown);
   260→  }, [editor]);
   261→
   262→  // Cmd+H — open / close find & replace bar
   263→  useEffect(() => {
   264→    function onKeyDown(e: KeyboardEvent) {
   265→      if (!(e.metaKey || e.ctrlKey) || e.key?.toLowerCase() !== "h") return;
   266→      if (!editor?.isFocused && !showFindReplace) return;
   267→      e.preventDefault();
   268→      setShowFindReplace((v) => {
   269→        if (v) editor?.chain().focus().run();
   270→        return !v;
   271→      });
   272→    }
   273→    window.addEventListener("keydown", onKeyDown);
   274→    return () => window.removeEventListener("keydown", onKeyDown);
   275→  }, [editor, showFindReplace]);
   276→
   277→  // Insert / Format menu commands forwarded from the native menu bar
   278→  useEffect(() => {
   279→    let mounted = true;
   280→    let unlisten: (() => void) | undefined;
   281→    listen<string>("menu-action", (event) => {
   282→      if (!editor || linkDialog) return;
   283→      switch (event.payload) {
   284→        case "format-bold":
   285→          editor.chain().focus().toggleBold().run();
   286→          break;
   287→        case "format-italic":
   288→          editor.chain().focus().toggleItalic().run();
   289→          break;
   290→        case "format-strike":
   291→          editor.chain().focus().toggleStrike().run();
   292→          break;
   293→        case "format-code":
   294→          editor.chain().focus().toggleCode().run();
   295→          break;
   296→        case "format-heading-1":
   297→          editor.chain().focus().toggleHeading({ level: 1 }).run();
   298→          break;
   299→        case "format-heading-2":
   300→          editor.chain().focus().toggleHeading({ level: 2 }).run();
   301→          break;
   302→        case "format-heading-3":
   303→          editor.chain().focus().toggleHeading({ level: 3 }).run();
   304→          break;
   305→        case "format-blockquote":
   306→          editor.chain().focus().toggleBlockquote().run();
   307→          break;
   308→        case "format-bullet-list":
   309→          editor.chain().focus().toggleBulletList().run();
   310→          break;
   311→        case "format-ordered-list":
   312→          editor.chain().focus().toggleOrderedList().run();
   313→          break;
   314→        case "insert-link": {
   315→          const href = editor.getAttributes("link").href ?? "";
   316→          setLinkDialog({ href });
   317→          break;
   318→        }
   319→        case "insert-code-block":
   320→          editor.chain().focus().toggleCodeBlock().run();
   321→          break;
   322→        case "insert-hr":
   323→          editor.chain().focus().setHorizontalRule().run();
   324→          break;
   325→        case "insert-table":
   326→          editor.chain().focus().insertTable({ rows: 3, cols: 3, withHeaderRow: true }).run();
   327→          break;
   328→      }
   329→    }).then((fn) => {
   330→      if (mounted) {
   331→        unlisten = fn;
   332→      } else {
   333→        fn();
   334→      }
   335→    });
   336→    return () => {
   337→      mounted = false;
   338→      unlisten?.();
   339→    };
   340→  }, [editor, linkDialog]);
   341→
   342→  return (
   343→    <div className="editor-wrapper">
   344→      <div ref={scrollRef} className="editor-scroll">
   345→        <EditorContent editor={editor} />
   346→      </div>
   347→      {editor && showFindReplace && (
   348→        <FindReplaceBar
   349→          editor={editor}
   350→          onClose={() => {
   351→            setShowFindReplace(false);
   352→            editor.chain().focus().run();
   353→          }}
   354→        />
   355→      )}
   356→      {editor && <TableControls editor={editor} />}
   357→      {editor && (
   358→        <BubbleMenu
   359→          editor={editor}
   360→          onLinkClick={() => {
   361→            const href = editor.getAttributes("link").href ?? "";
   362→            setLinkDialog({ href });
   363→          }}
   364→        />
   365→      )}
   366→      {linkDialog && (
   367→        <LinkDialog
   368→          initialHref={linkDialog.href}
   369→          onApply={(url) => {
   370→            editor?.chain().focus().extendMarkRange("link").setLink({ href: url }).run();
   371→            setLinkDialog(null);
   372→          }}
   373→          onRemove={() => {
   374→            editor?.chain().focus().extendMarkRange("link").unsetLink().run();
   375→            setLinkDialog(null);
   376→          }}
   377→          onCancel={() => setLinkDialog(null)}
   378→        />
   379→      )}
   380→    </div>
   381→  );
   382→}
   383→

