     1→/* Tiptap / ProseMirror editor styles */
     2→
     3→.editor-wrapper {
     4→  flex: 1;
     5→  display: flex;
     6→  flex-direction: column;
     7→  overflow: hidden;
     8→  background: var(--color-surface);
     9→}
    10→
    11→.editor-scroll {
    12→  flex: 1;
    13→  overflow-y: auto;
    14→  padding: 48px 0;
    15→}
    16→
    17→.ProseMirror {
    18→  max-width: 680px;
    19→  margin: 0 auto;
    20→  padding: 0 24px;
    21→  font-family: var(--font-editor);
    22→  font-size: var(--font-editor-size, 17px);
    23→  line-height: 1.75;
    24→  color: var(--color-fg);
    25→  outline: none;
    26→  min-height: 100%;
    27→}
    28→
    29→/* Headings */
    30→.ProseMirror h1 {
    31→  font-size: 2em;
    32→  font-weight: 700;
    33→  line-height: 1.25;
    34→  margin-top: 1.5em;
    35→  margin-bottom: 0.5em;
    36→  color: var(--color-fg);
    37→}
    38→
    39→.ProseMirror h2 {
    40→  font-size: 1.5em;
    41→  font-weight: 600;
    42→  line-height: 1.3;
    43→  margin-top: 1.4em;
    44→  margin-bottom: 0.4em;
    45→}
    46→
    47→.ProseMirror h3 {
    48→  font-size: 1.2em;
    49→  font-weight: 600;
    50→  line-height: 1.35;
    51→  margin-top: 1.3em;
    52→  margin-bottom: 0.35em;
    53→}
    54→
    55→/* First heading at top — no extra top margin */
    56→.ProseMirror > h1:first-child,
    57→.ProseMirror > h2:first-child,
    58→.ProseMirror > h3:first-child {
    59→  margin-top: 0;
    60→}
    61→
    62→/* Paragraphs */
    63→.ProseMirror p {
    64→  margin-bottom: 1em;
    65→}
    66→
    67→.ProseMirror p:last-child {
    68→  margin-bottom: 0;
    69→}
    70→
    71→/* Bold & Italic */
    72→.ProseMirror strong {
    73→  font-weight: 700;
    74→}
    75→
    76→.ProseMirror em {
    77→  font-style: italic;
    78→}
    79→
    80→/* Inline code */
    81→.ProseMirror code {
    82→  font-family: var(--font-mono);
    83→  font-size: 0.875em;
    84→  background: var(--color-surface-active);
    85→  border: 1px solid var(--color-border);
    86→  border-radius: 3px;
    87→  padding: 0.1em 0.35em;
    88→}
    89→
    90→/* Code block */
    91→.ProseMirror pre {
    92→  font-family: var(--font-mono);
    93→  font-size: 0.875em;
    94→  background: var(--color-surface-subtle);
    95→  border: 1px solid var(--color-border);
    96→  border-radius: 6px;
    97→  padding: 16px 20px;
    98→  overflow-x: auto;
    99→  margin: 1.2em 0;
   100→  line-height: 1.6;
   101→}
   102→
   103→.ProseMirror pre code {
   104→  background: none;
   105→  border: none;
   106→  padding: 0;
   107→  font-size: 1em;
   108→}
   109→
   110→/* Code block with language bar — reset pre so bar and block form one unified unit */
   111→.ProseMirror .code-block-wrapper pre {
   112→  margin: 0;
   113→  border-top: none;
   114→  border-top-left-radius: 0;
   115→  border-top-right-radius: 0;
   116→  padding-top: 12px;
   117→}
   118→
   119→/* Blockquote */
   120→.ProseMirror blockquote {
   121→  border-left: 3px solid var(--color-accent);
   122→  padding-left: 1em;
   123→  margin: 1.2em 0;
   124→  color: var(--color-fg-muted);
   125→  font-style: italic;
   126→}
   127→
   128→/* Lists */
   129→.ProseMirror ul,
   130→.ProseMirror ol {
   131→  padding-left: 1.5em;
   132→  margin: 0.75em 0;
   133→}
   134→
   135→.ProseMirror li {
   136→  margin-bottom: 0.25em;
   137→}
   138→
   139→/* Horizontal rule */
   140→.ProseMirror hr {
   141→  border: none;
   142→  border-top: 1px solid var(--color-border);
   143→  margin: 2em 0;
   144→}
   145→
   146→/* Links */
   147→.ProseMirror a {
   148→  color: var(--color-accent);
   149→  text-decoration: underline;
   150→  text-underline-offset: 2px;
   151→}
   152→
   153→/* Images */
   154→.ProseMirror img {
   155→  max-width: 100%;
   156→  border-radius: 6px;
   157→  margin: 1em 0;
   158→}
   159→
   160→/* Placeholder */
   161→.ProseMirror p.is-editor-empty:first-child::before {
   162→  content: attr(data-placeholder);
   163→  color: var(--color-fg-subtle);
   164→  pointer-events: none;
   165→  float: left;
   166→  height: 0;
   167→  font-family: var(--font-ui);
   168→  font-style: normal;
   169→}
   170→
   171→/* Selection */
   172→.ProseMirror ::selection {
   173→  background: var(--color-accent-subtle);
   174→}
   175→
   176→/* Focus ring — hidden, we style it via the wrapper */
   177→.ProseMirror:focus {
   178→  outline: none;
   179→}
   180→
   181→/* ── Syntax highlighting (lowlight/highlight.js tokens) ─── */
   182→.hljs-comment,
   183→.hljs-quote {
   184→  color: var(--color-syntax-comment);
   185→  font-style: italic;
   186→}
   187→
   188→.hljs-keyword,
   189→.hljs-selector-tag,
   190→.hljs-built_in,
   191→.hljs-name,
   192→.hljs-tag {
   193→  color: var(--color-syntax-keyword);
   194→}
   195→
   196→.hljs-string,
   197→.hljs-title,
   198→.hljs-section,
   199→.hljs-attribute,
   200→.hljs-literal,
   201→.hljs-template-tag,
   202→.hljs-template-variable,
   203→.hljs-type,
   204→.hljs-addition {
   205→  color: var(--color-syntax-string);
   206→}
   207→
   208→.hljs-deletion,
   209→.hljs-selector-attr,
   210→.hljs-selector-pseudo,
   211→.hljs-meta {
   212→  color: var(--color-syntax-meta);
   213→}
   214→
   215→.hljs-doctag,
   216→.hljs-attr {
   217→  color: var(--color-syntax-attr);
   218→}
   219→
   220→.hljs-symbol,
   221→.hljs-bullet,
   222→.hljs-link,
   223→.hljs-subst,
   224→.hljs-variable,
   225→.hljs-number,
   226→.hljs-regexp {
   227→  color: var(--color-syntax-number);
   228→}
   229→
   230→.hljs-emphasis {
   231→  font-style: italic;
   232→}
   233→
   234→.hljs-strong {
   235→  font-weight: bold;
   236→}
   237→
   238→/* ── Typora-style inline syntax reveal ─────────── */
   239→.inline-syntax {
   240→  font-family: var(--font-mono);
