   152→/// Canonicalize `requested` and verify it is inside `workspace_root`.
   153→fn validate_path(workspace_root: &Path, requested: &str) -> Result<PathBuf, String> {
   154→    let canonical_root =
   155→        std::fs::canonicalize(workspace_root).map_err(|e| format!("workspace root: {e}"))?;
   156→    let canonical_path =
   157→        std::fs::canonicalize(requested).map_err(|e| format!("invalid path: {e}"))?;
   158→    if !canonical_path.starts_with(&canonical_root) {
   159→        return Err("path is outside the opened workspace".to_string());
   160→    }
   161→    Ok(canonical_path)
   162→}
   163→
   164→/// Validate that a prospective new path's parent exists inside the workspace root.
   165→fn validate_new_path(workspace_root: &Path, requested: &str) -> Result<PathBuf, String> {
   166→    let canonical_root =
   167→        std::fs::canonicalize(workspace_root).map_err(|e| format!("workspace root: {e}"))?;
   168→    let new_path = PathBuf::from(requested);
   169→    let parent = new_path
   170→        .parent()
   171→        .ok_or("path has no parent directory")?;
   172→    let canonical_parent =
   173→        std::fs::canonicalize(parent).map_err(|e| format!("invalid parent path: {e}"))?;
   174→    if !canonical_parent.starts_with(&canonical_root) {
   175→        return Err("path is outside the opened workspace".to_string());
   176→    }
   177→    Ok(new_path)
   178→}
