   203→#[tauri::command]
   204→async fn open_workspace_at_path(
   205→    path: String,
   206→    state: State<'_, WorkspaceState>,
   207→) -> Result<Option<WorkspaceResult>, String> {
   208→    let root = PathBuf::from(&path);
   209→    if !root.is_dir() {
   210→        return Ok(None);
   211→    }
   212→
   213→    let name = root
   214→        .file_name()
   215→        .map(|n| n.to_string_lossy().to_string())
   216→        .unwrap_or_else(|| root.to_string_lossy().to_string());
   217→
   218→    let content_dir = root.join("content");
   219→    let tree_root = if content_dir.is_dir() { content_dir } else { root.clone() };
   220→
   221→    *state.tree_root.lock().map_err(|e| e.to_string())? = Some(tree_root.clone());
   222→    *state.workspace_root.lock().map_err(|e| e.to_string())? = Some(root.clone());
   223→
   224→    let is_amytis_workspace = root.join("site.config.ts").is_file() && root.join("content").is_dir();
   225→    let tree = walk_dir(&tree_root);
   226→
   227→    Ok(Some(WorkspaceResult {
   228→        name,
   229→        root_path: root.to_string_lossy().to_string(),
   230→        tree_root: tree_root.to_string_lossy().to_string(),
   231→        tree,
   232→        is_amytis_workspace,
   233→    }))
   234→}
