   337→/// Search all markdown files under `path` for lines containing `query` (case-insensitive).
   338→fn search_dir(path: &Path, query: &str) -> Vec<SearchResult> {
   339→    let Ok(entries) = std::fs::read_dir(path) else {
   340→        return Vec::new();
   341→    };
   342→    let mut entries: Vec<_> = entries.flatten().collect();
   343→    entries.sort_by_key(|e| e.file_name());
   344→
   345→    let mut results = Vec::new();
   346→    for entry in entries {
   347→        let entry_path = entry.path();
   348→        let name = entry.file_name().to_string_lossy().to_string();
   349→        if name.starts_with('.') {
   350→            continue;
   351→        }
   352→        // Skip symlinks to prevent traversal outside the workspace
   353→        if entry.file_type().map(|ft| ft.is_symlink()).unwrap_or(false) {
   354→            continue;
   355→        }
   356→        if entry_path.is_dir() {
   357→            results.extend(search_dir(&entry_path, query));
   358→        } else {
   359→            let ext = entry_path.extension().and_then(|e| e.to_str()).unwrap_or("");
   360→            if ext != "md" && ext != "mdx" {
   361→                continue;
   362→            }
   363→            let Ok(content) = std::fs::read_to_string(&entry_path) else {
   364→                continue;
   365→            };
   366→            let q = query.to_lowercase();
   367→            let matches: Vec<SearchMatch> = content
   368→                .lines()
   369→                .enumerate()
   370→                .filter_map(|(i, line)| {
   371→                    if line.to_lowercase().contains(&q) {
   372→                        Some(SearchMatch {
   373→                            line_number: i + 1,
   374→                            line_content: line.trim().to_string(),
   375→                        })
   376→                    } else {
   377→                        None
   378→                    }
   379→                })
   380→                .collect();
   381→            if !matches.is_empty() {
   382→                let (title, _, _) = read_frontmatter_meta(&entry_path);
   383→                results.push(SearchResult {
   384→                    path: entry_path.to_string_lossy().to_string(),
   385→                    title,
   386→                    matches,
   387→                });
   388→            }
   389→        }
   390→    }
   391→    results
   392→}
