   394→#[tauri::command]
   395→fn search_workspace(query: String, state: State<'_, WorkspaceState>) -> Result<Vec<SearchResult>, String> {
   396→    if query.trim().is_empty() {
   397→        return Ok(Vec::new());
   398→    }
   399→    // Clone root before releasing the lock so the mutex is not held during search
   400→    let root = {
