   418→// ── Content types ──────────────────────────────────────────────────────────
   419→
   420→#[derive(Serialize)]
   421→#[serde(rename_all = "camelCase")]
   422→struct ContentType {
   423→    name: String,
   424→}
   425→
   426→/// Best-effort scanner: find `contentTypes` in `site.config.ts` and extract
   427→/// the top-level key names (post, page, note, …). Returns empty vec on any
   428→/// parse failure so callers gracefully degrade to the default frontmatter.
   429→fn parse_content_types(config_path: &Path) -> Vec<ContentType> {
   430→    use std::io::{BufRead, BufReader};
   431→    let Ok(file) = std::fs::File::open(config_path) else {
   432→        return Vec::new();
   433→    };
   434→    let mut reader = BufReader::new(file);
   435→    let mut type_names: Vec<ContentType> = Vec::new();
   436→    let mut depth: i32 = 0;
   437→    let mut found_content_types = false;
   438→    let mut content_types_depth: Option<i32> = None;
   439→    let mut line = String::new();
   440→
   441→    loop {
   442→        line.clear();
   443→        if reader.read_line(&mut line).unwrap_or(0) == 0 {
   444→            break;
   445→        }
   446→        let trimmed = line.trim();
   447→        let open_count = line.chars().filter(|&c| c == '{').count() as i32;
   448→        let close_count = line.chars().filter(|&c| c == '}').count() as i32;
   449→
   450→        match content_types_depth {
   451→            None if !found_content_types => {
   452→                if trimmed.contains("contentTypes") {
   453→                    found_content_types = true;
   454→                    depth += open_count - close_count;
   455→                    if open_count > 0 {
   456→                        content_types_depth = Some(depth);
   457→                    }
   458→                } else {
   459→                    depth += open_count - close_count;
   460→                }
   461→            }
   462→            None => {
   463→                // found keyword, waiting for opening brace
   464→                depth += open_count - close_count;
   465→                if open_count > 0 {
   466→                    content_types_depth = Some(depth);
   467→                }
   468→            }
   469→            Some(ct_depth) => {
   470→                let prev_depth = depth;
   471→                depth += open_count - close_count;
   472→                if depth < ct_depth {
   473→                    break;
   474→                }
   475→                if prev_depth == ct_depth {
   476→                    if let Some(name) = extract_ts_key(trimmed) {
   477→                        type_names.push(ContentType { name });
   478→                    }
   479→                }
   480→            }
   481→        }
   482→    }
   483→    type_names
   484→}
   485→
   486→fn extract_ts_key(line: &str) -> Option<String> {
   487→    let line = line.trim();
   488→    if line.starts_with("//") || line.starts_with('*') || line.starts_with("/*") {
   489→        return None;
   490→    }
   491→    let end = line.find(':')?;
   492→    let key = line[..end].trim().trim_matches('"').trim_matches('\'');
   493→    if !key.is_empty() && key.chars().all(|c| c.is_alphanumeric() || c == '_') {
   494→        Some(key.to_string())
   495→    } else {
   496→        None
   497→    }
   498→}
   499→
   500→#[tauri::command]
   501→fn get_content_types(state: State<'_, WorkspaceState>) -> Result<Vec<ContentType>, String> {
   502→    let root_guard = state.workspace_root.lock().map_err(|e| e.to_string())?;
   503→    let root = match root_guard.as_ref() {
   504→        Some(r) => r.clone(),
   505→        None => return Ok(Vec::new()),
   506→    };
   507→    drop(root_guard);
   508→    let config = root.join("site.config.ts");
   509→    if !config.is_file() {
   510→        return Ok(Vec::new());
   511→    }
   512→    Ok(parse_content_types(&config))
   513→}
