   515→// ── Git integration ────────────────────────────────────────────────────────
   516→
   517→#[derive(Serialize)]
   518→#[serde(rename_all = "camelCase")]
   519→struct GitFileStatus {
   520→    path: String,
   521→    status: String,
   522→}
   523→
   524→/// Run a git subcommand rooted at `root`. Returns stdout on success or an
   525→/// error string (stderr) on failure. Returns an empty string if git is not
   526→/// found, so callers can treat a missing git as a graceful no-op.
   527→fn run_git(root: &str, args: &[&str]) -> Result<String, String> {
   528→    let mut cmd_args = vec!["-C", root];
   529→    cmd_args.extend_from_slice(args);
   530→    let output = std::process::Command::new("git")
   531→        .args(&cmd_args)
   532→        .output()
   533→        .map_err(|_| "git not found".to_string())?;
   534→    if !output.status.success() {
   535→        let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
   536→        return Err(if stderr.is_empty() { "git command failed".to_string() } else { stderr });
   537→    }
   538→    Ok(String::from_utf8_lossy(&output.stdout).to_string())
   539→}
   540→
   541→#[tauri::command]
   542→fn get_git_status(state: State<'_, WorkspaceState>) -> Result<Vec<GitFileStatus>, String> {
   543→    let root_guard = state.tree_root.lock().map_err(|e| e.to_string())?;
   544→    let root = match root_guard.as_ref() {
   545→        Some(r) => r.clone(),
   546→        None => return Ok(Vec::new()),
   547→    };
   548→    drop(root_guard);
   549→    let root_str = root.to_string_lossy().to_string();
   550→
   551→    // Find the git repo root (may differ from tree_root if content/ is a subdir)
   552→    let git_root = match run_git(&root_str, &["rev-parse", "--show-toplevel"]) {
   553→        Ok(s) => s.trim().to_string(),
   554→        Err(_) => return Ok(Vec::new()), // not a git repo or git not found
   555→    };
   556→
   557→    let porcelain = match run_git(&git_root, &["status", "--porcelain"]) {
   558→        Ok(s) => s,
   559→        Err(_) => return Ok(Vec::new()),
   560→    };
   561→
   562→    let mut statuses = Vec::new();
   563→    for line in porcelain.lines() {
   564→        if line.len() < 4 {
   565→            continue;
   566→        }
   567→        let xy = &line[..2];
   568→        let path_part = line[3..].trim();
   569→        // Handle renames: "R old -> new" — take the destination
   570→        let file_path = if path_part.contains(" -> ") {
   571→            path_part.split(" -> ").nth(1).unwrap_or(path_part)
   572→        } else {
   573→            path_part
   574→        };
   575→        let abs_path = PathBuf::from(&git_root).join(file_path).to_string_lossy().into_owned();
   576→        let status = if xy.starts_with('?') {
   577→            "untracked"
   578→        } else if xy.chars().next().map(|c| c != ' ').unwrap_or(false) {
   579→            "staged"
   580→        } else {
   581→            "modified"
   582→        };
   583→        statuses.push(GitFileStatus { path: abs_path, status: status.to_string() });
   584→    }
   585→    Ok(statuses)
   586→}
   587→
   588→#[tauri::command]
   589→fn get_git_branch(state: State<'_, WorkspaceState>) -> Result<String, String> {
   590→    let root_guard = match state.tree_root.lock() {
   591→        Ok(g) => g,
   592→        Err(_) => return Ok(String::new()),
   593→    };
   594→    let root = match root_guard.as_ref() {
   595→        Some(r) => r.clone(),
   596→        None => return Ok(String::new()),
   597→    };
   598→    drop(root_guard);
   599→    Ok(
   600→        run_git(&root.to_string_lossy(), &["rev-parse", "--abbrev-ref", "HEAD"])
   601→            .map(|s| s.trim().to_string())
   602→            .unwrap_or_default(),
   603→    )
   604→}
