    15→interface UseWorkspaceOptions {
    16→  showToast: (msg: string) => void;
    17→  flushPendingSave: () => Promise<void>;
    18→  handleCloseFile: () => Promise<void>;
    19→  handleSelectFile: (node: FileNode) => Promise<void>;
    20→  selectedFile: FileNode | null;
    21→  selectedPathRef: MutableRefObject<string | null>;
    22→  setSelectedFile: (node: FileNode | null) => void;
    23→  resetFileState: () => void;
    24→}
    25→
    26→function findNode(nodes: FileNode[], path: string): FileNode | undefined {
    27→  for (const n of nodes) {
    28→    if (n.path === path) return n;
    29→    if (n.children) {
    30→      const found = findNode(n.children, path);
    31→      if (found) return found;
    32→    }
    33→  }
    34→}
    35→
    36→export function useWorkspace({
    37→  showToast,
    38→  flushPendingSave,
    39→  handleCloseFile,
    40→  handleSelectFile,
    41→  selectedFile,
    42→  selectedPathRef,
    43→  setSelectedFile,
    44→  resetFileState,
    45→}: UseWorkspaceOptions) {
    46→  const [tree, setTree] = useState<FileNode[]>([]);
    47→  const [workspaceName, setWorkspaceName] = useState<string | null>(null);
    48→  const [workspaceRoot, setWorkspaceRoot] = useState<string | null>(null);
    49→  const [workspaceRootPath, setWorkspaceRootPath] = useState<string | null>(null);
    50→  const [isAmytisWorkspace, setIsAmytisWorkspace] = useState(false);
    51→  const [renamingPath, setRenamingPath] = useState<string | null>(null);
    52→
    53→  const refreshTree = useCallback(async (): Promise<FileNode[]> => {
    54→    try {
    55→      const updated = await invoke<FileNode[]>("list_workspace");
    56→      setTree(updated);
    57→      return updated;
    58→    } catch (err) {
    59→      console.error("Failed to refresh tree:", err);
    60→      return [];
    61→    }
    62→  }, []);
    63→
    64→  const applyWorkspaceResult = useCallback(
    65→    (result: WorkspaceResult) => {
    66→      setTree(result.tree);
    67→      setWorkspaceName(result.name);
    68→      setWorkspaceRoot(result.treeRoot);
    69→      setWorkspaceRootPath(result.rootPath);
    70→      setIsAmytisWorkspace(result.isAmytisWorkspace);
    71→      resetFileState();
    72→      if (!result.isAmytisWorkspace) {
    73→        showToast("This folder doesn't look like an Amytis workspace.");
    74→      }
    75→    },
    76→    [resetFileState, showToast]
    77→  );
    78→
    79→  const openWorkspaceAtPath = useCallback(
    80→    async (path: string) => {
    81→      await flushPendingSave();
    82→      try {
    83→        const result = await invoke<WorkspaceResult | null>("open_workspace_at_path", { path });
    84→        if (result) applyWorkspaceResult(result);
    85→        else showToast("Could not open workspace — path may no longer be valid.");
    86→      } catch (err) {
    87→        console.error("Failed to open workspace:", err);
    88→        showToast(`Failed to open workspace: ${err}`);
    89→      }
    90→    },
    91→    [flushPendingSave, showToast, applyWorkspaceResult]
    92→  );
    93→
    94→  const handleOpenWorkspace = useCallback(async () => {
    95→    await flushPendingSave();
    96→    try {
    97→      const result = await invoke<WorkspaceResult | null>("open_workspace");
    98→      if (result) applyWorkspaceResult(result);
    99→    } catch (err) {
   100→      console.error("Failed to open workspace:", err);
   101→      showToast(`Failed to open workspace: ${err}`);
   102→    }
   103→  }, [flushPendingSave, showToast, applyWorkspaceResult]);
   104→
   105→  async function handleNewFile(dirPath: string, filename: string, contentType?: string) {
   106→    const slug = filename.replace(/\.md$/, "");
   107→    const filePath = `${dirPath}/${slug}.md`;
   108→    const content = contentType
   109→      ? createTypedFrontmatter(slug, contentType)
   110→      : createAmytisFrontmatter(slug);
   111→    try {
   112→      await invoke("create_file", { path: filePath, content });
   113→      const updated = await refreshTree();
   114→      const newNode = findNode(updated, filePath);
   115→      if (newNode) await handleSelectFile(newNode);
   116→    } catch (err) {
   117→      console.error("Failed to create file:", err);
   118→      showToast(`Failed to create file: ${err}`);
   119→    }
   120→  }
   121→
   122→  async function handleRename(node: FileNode, newName: string) {
   123→    setRenamingPath(null);
   124→    await flushPendingSave();
   125→    const dir = node.path.substring(0, node.path.lastIndexOf("/"));
   126→    const ext = node.extension ?? ".md";
   127→    const newPath = `${dir}/${newName}${newName.endsWith(ext) ? "" : ext}`;
   128→    try {
   129→      await invoke("rename_file", { oldPath: node.path, newPath });
   130→      const updated = await refreshTree();
   131→      if (selectedFile?.path === node.path) {
   132→        const renamed = findNode(updated, newPath);
   133→        if (renamed) {
   134→          selectedPathRef.current = newPath;
   135→          setSelectedFile(renamed);
   136→        }
   137→      }
   138→    } catch (err) {
   139→      console.error("Failed to rename file:", err);
   140→      showToast(`Failed to rename: ${err}`);
   141→    }
   142→  }
   143→
   144→  async function handleDelete(node: FileNode) {
   145→    const confirmed = window.confirm(`Move "${node.name}" to Trash?`);
   146→    if (!confirmed) return;
   147→    if (selectedFile?.path === node.path) {
   148→      await flushPendingSave();
   149→    }
   150→    try {
   151→      await invoke("trash_file", { path: node.path });
   152→      if (selectedFile?.path === node.path) await handleCloseFile();
   153→      await refreshTree();
   154→    } catch (err) {
   155→      console.error("Failed to delete file:", err);
   156→      showToast(`Failed to delete: ${err}`);
   157→    }
   158→  }
   159→
   160→  return {
   161→    tree,
   162→    workspaceName,
   163→    workspaceRoot,
   164→    workspaceRootPath,
   165→    isAmytisWorkspace,
   166→    renamingPath,
   167→    setRenamingPath,
   168→    handleOpenWorkspace,
   169→    openWorkspaceAtPath,
   170→    handleNewFile,
   171→    handleRename,
   172→    handleDelete,
   173→  };
   174→}
