   284→fn list_workspace(state: State<'_, WorkspaceState>) -> Result<Vec<FileNode>, String> {
   285→    let root_guard = state.tree_root.lock().map_err(|e| e.to_string())?;
   286→    let root = root_guard.as_ref().ok_or("no workspace open")?;
   287→    Ok(walk_dir(root))
   288→}
