      mounted = false;
      unlisten?.();
    };
  }, [
    modal,
    commitDialog,
    switcherOpen,
    workspaceSwitcherOpen,
    workspaceRoot,
    tree,
    isGitRepo,
    getBranch,
    parsedFrontmatter,
