/* ── Right-side properties panel ─────────────── */
.properties-panel {
  width: 220px;
  min-width: 220px;
  background: var(--color-surface-subtle);
  border-left: 1px solid var(--color-border);
  display: flex;
  flex-direction: column;
  overflow-y: auto;
  overflow-x: hidden;
  user-select: none;
  transition:
    width 0.2s ease,
    min-width 0.2s ease,
    border-left-color 0.2s ease;
}

.properties-panel.hidden {
  width: 0;
  min-width: 0;
  border-left-color: transparent;
  visibility: hidden;
}

/* ── Header: type + status badge ─────────────── */
.prop-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 14px 10px;
  border-bottom: 1px solid var(--color-border);
  gap: 8px;
}

.prop-status-badge {
  flex-shrink: 0;
  font-size: 10px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  padding: 2px 7px;
  border-radius: 4px;
  cursor: pointer;
  color: var(--color-warning);
  background: var(--color-warning-subtle);
  transition:
    color 0.15s,
    background 0.15s,
    opacity 0.15s;
}

.prop-status-badge:hover {
  opacity: 0.8;
}

.prop-status-badge.published {
  color: var(--color-accent);
  background: var(--color-accent-subtle);
}

/* ── Body ────────────────────────────────────── */
.properties-body {
  padding: 14px 14px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

/* ── Individual field ────────────────────────── */
.prop-field {
  display: flex;
  flex-direction: column;
  gap: 3px;
}

.prop-label {
  font-size: 10px;
  font-weight: 600;
  color: var(--color-fg-subtle);
  text-transform: uppercase;
  letter-spacing: 0.07em;
}

.prop-value {
  font-size: 13px;
  color: var(--color-fg-muted);
  line-height: 1.4;
  overflow-wrap: anywhere;
  word-wrap: break-word;
}

/* ── Slug (read-only) ────────────────────────── */
.prop-slug {
  font-size: 12px;
  color: var(--color-fg-subtle);
  font-family: var(--font-mono, monospace);
  word-break: break-all;
  padding: 2px 0;
}

/* ── Editable areas ──────────────────────────── */
.prop-editable-area {
  display: block;
  width: 100%;
  text-align: left;
  padding: 3px 6px;
  margin: 0 -6px;
  border-radius: 4px;
  cursor: text;
  transition: background 0.15s;
  box-sizing: content-box;
}

.prop-editable-area:hover {
  background: var(--color-surface-hover);
}

/* ── Tag chip input ──────────────────────────── */
.tag-input-area {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 4px;
  padding: 4px 6px;
  border: 1px solid var(--color-border);
  border-radius: 5px;
  background: var(--color-surface);
  cursor: text;
  min-height: 28px;
  transition: border-color 0.15s;
}

.tag-input-area:focus-within {
  border-color: var(--color-accent);
}

.prop-tag {
  display: inline-flex;
  align-items: center;
  gap: 3px;
  font-size: 11px;
  color: var(--color-accent);
  background: var(--color-accent-subtle);
  border-radius: 4px;
  padding: 1px 5px 1px 7px;
  line-height: 1.6;
}

.prop-tag-remove {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 13px;
  line-height: 1;
  color: var(--color-accent);
  opacity: 0.6;
  padding: 0 1px;
  border-radius: 2px;
  transition: opacity 0.1s;
  cursor: pointer;
}

.prop-tag-remove:hover {
  opacity: 1;
}

.tag-input {
  flex: 1;
  min-width: 60px;
  font-size: 12px;
  font-family: var(--font-ui);
  color: var(--color-fg);
  background: transparent;
  border: none;
  outline: none;
  padding: 0;
}

.tag-input::placeholder {
  color: var(--color-fg-subtle);
}

/* ── Add field row ───────────────────────────── */
.prop-add-field-btn {
  align-self: flex-start;
  font-size: 11px;
  color: var(--color-fg-subtle);
  padding: 2px 4px;
  border-radius: 4px;
  cursor: pointer;
  transition:
    color 0.15s,
    background 0.15s;
}

.prop-add-field-btn:hover {
  color: var(--color-fg-muted);
  background: var(--color-surface-hover);
}

.prop-add-row {
  display: flex;
  gap: 6px;
}

/* ── Type selector ───────────────────────────── */
.prop-type-row {
  display: flex;
  align-items: center;
  gap: 5px;
  min-width: 0;
}

.prop-type-select {
  font-size: 12px;
  font-family: var(--font-ui);
  font-weight: 500;
  color: var(--color-fg-muted);
  background: transparent;
  border: none;
  outline: none;
  cursor: pointer;
  text-transform: capitalize;
  padding: 0 2px;
}

.prop-type-select:focus {
  color: var(--color-fg);
}

/* ── Inline input ────────────────────────────── */
.prop-input {
  width: 100%;
  height: 28px;
  padding: 0 6px;
  font-size: 13px;
  font-family: var(--font-ui);
  color: var(--color-fg);
  background: var(--color-surface);
  border: 1px solid var(--color-border-strong);
  border-radius: 5px;
  outline: none;
  box-sizing: border-box;
  transition: border-color 0.15s;
}

.prop-input:focus {
  border-color: var(--color-accent);
}

.prop-input::placeholder {
  color: var(--color-fg-subtle);
}

.prop-input--sm {
  height: 26px;
  font-size: 12px;
}

.prop-input--date {
  font-size: 12px;
  cursor: pointer;
}

/* ── Divider ─────────────────────────────────── */
.prop-divider {
  height: 1px;
  background: var(--color-border);
}

