/* App shell */
.app {
  display: flex;
  flex-direction: column;
  height: 100vh;
  width: 100vw;
  overflow: hidden;
  background: var(--color-surface);
}

.app-body {
  display: flex;
  flex: 1;
  overflow: hidden;
}

.editor-column {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

/* ── Zen mode ────────────────────────────────── */
.app[data-zen] .statusbar {
  display: none;
}

.app[data-zen] .sidebar,
.app[data-zen] .search-panel {
  display: none;
}

.app[data-zen] .properties-panel {
  display: none;
}

.app[data-zen] .editor-scroll {
  padding-top: 10vh;
  padding-bottom: 10vh;
}

/* ── Toasts ──────────────────────────────────── */
.toast-container {
  position: fixed;
  bottom: calc(var(--statusbar-height) + 12px);
  left: 50%;
  transform: translateX(-50%);
  display: flex;
  flex-direction: column;
  gap: 6px;
  z-index: 1000;
  pointer-events: none;
}

.toast {
  background: var(--color-fg);
  color: var(--color-surface);
  font-size: 12.5px;
  padding: 7px 16px;
  border-radius: 6px;
  white-space: nowrap;
  animation: toast-in 0.15s ease;
}

@keyframes toast-in {
  from {
    opacity: 0;
    transform: translateY(6px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

