import { invoke } from "@tauri-apps/api/core";
import { listen } from "@tauri-apps/api/event";
import { InputRule } from "@tiptap/core";
import CodeBlockLowlight from "@tiptap/extension-code-block-lowlight";
import Link from "@tiptap/extension-link";
import { Mathematics } from "@tiptap/extension-mathematics";
import Placeholder from "@tiptap/extension-placeholder";
import { Table } from "@tiptap/extension-table";
import { TableCell } from "@tiptap/extension-table-cell";
import { TableHeader } from "@tiptap/extension-table-header";
import { TableRow } from "@tiptap/extension-table-row";
import Typography from "@tiptap/extension-typography";
import { EditorContent, ReactNodeViewRenderer, useEditor } from "@tiptap/react";
import StarterKit from "@tiptap/starter-kit";
import { common, createLowlight } from "lowlight";
import { useEffect, useRef, useState } from "react";
import { Markdown } from "tiptap-markdown";
import { FindReplace } from "../lib/tiptap/FindReplace";
import { ImageRenderer } from "../lib/tiptap/ImageRenderer";
import { InlineEditMode } from "../lib/tiptap/InlineEditMode";
import { LinkPreview } from "../lib/tiptap/LinkPreview";
import { TextFolding } from "../lib/tiptap/TextFolding";
import { BubbleMenu } from "./BubbleMenu";
import { CodeBlockView } from "./CodeBlockView";
import { FindReplaceBar } from "./FindReplaceBar";
import { LinkDialog } from "./LinkDialog";
import { TableControls } from "./TableControls";
import "katex/dist/katex.min.css";
import "../styles/editor.css";

const lowlight = createLowlight(common);

const IMAGE_MIME = /^image\/(png|jpe?g|gif|webp|avif|svg\+xml)$/;

interface EditorProps {
  content?: string;
  filePath?: string;
  workspaceRootPath?: string;
  cdnBase?: string;
  typewriterMode?: boolean;
  spellCheck?: boolean;
  onWordCount?: (count: number) => void;
  onChange?: (markdown: string) => void;
}

export function Editor({
  content = "",
  filePath,
  workspaceRootPath,
  cdnBase,
  typewriterMode = false,
  spellCheck = true,
  onWordCount,
  onChange,
}: EditorProps) {
  const scrollRef = useRef<HTMLDivElement>(null);
  const typewriterRef = useRef(typewriterMode);
  useEffect(() => {
    typewriterRef.current = typewriterMode;
  }, [typewriterMode]);

  const [linkDialog, setLinkDialog] = useState<{ href: string } | null>(null);
  const [showFindReplace, setShowFindReplace] = useState(false);

  const editor = useEditor({
    extensions: [
      StarterKit.configure({ codeBlock: false }),
      CodeBlockLowlight.extend({
        addNodeView() {
          return ReactNodeViewRenderer(CodeBlockView);
        },
      }).configure({ lowlight }),
      Markdown.configure({
        transformPastedText: true,
        transformCopiedText: true,
      }),
      Placeholder.configure({
        placeholder: "Start writing…",
      }),
      Typography,
      Link.extend({
        addInputRules() {
          return [
            new InputRule({
              // Match completed [text](url) at the cursor
              find: /\[([^[\]]+)\]\(([^()]+)\)$/,
              handler: ({ range, match, chain }) => {
                const [, text, href] = match;
                chain()
                  .deleteRange(range)
                  .insertContentAt(range.from, {
                    type: "text",
                    text,
                    marks: [{ type: "link", attrs: { href, rel: "noopener noreferrer" } }],
                  })
                  .run();
              },
            }),
          ];
        },
      }).configure({
        openOnClick: false,
        HTMLAttributes: { rel: "noopener noreferrer" },
      }),
      ImageRenderer.configure({ filePath, workspaceRootPath, cdnBase }),
      Table.configure({ resizable: true }),
      TableRow,
      TableHeader,
      TableCell,
      Mathematics,
      LinkPreview,
      FindReplace,
      TextFolding,
      InlineEditMode,
    ],
    content,
    editorProps: {
      attributes: { spellcheck: spellCheck ? "true" : "false" },
      handlePaste(view, event) {
        const text = (event.clipboardData?.getData("text/plain") ?? "").trim();
        if (!/^https?:\/\/\S+$/.test(text)) return false;
        if (view.state.selection.empty) return false;
        // Paste a URL with text selected → apply it as a link mark
        event.preventDefault();
        const { from, to } = view.state.selection;
        const linkMark = view.state.schema.marks.link.create({
          href: text,
          rel: "noopener noreferrer",
        });
        view.dispatch(view.state.tr.addMark(from, to, linkMark));
        return true;
      },
      handleDrop(view, event) {
        const imageFiles = Array.from(event.dataTransfer?.files ?? [])
          .filter((f) => IMAGE_MIME.test(f.type))
          .map((f) => ({ name: f.name, srcPath: (f as { path?: string }).path }))
          .filter((f): f is { name: string; srcPath: string } => f.srcPath !== undefined);
        if (imageFiles.length === 0) return false;
        event.preventDefault();
        // Capture coords now; recompute position after async uploads settle
        // to avoid using a stale absolute offset if the document changes.
        const dropX = event.clientX;
        const dropY = event.clientY;
        Promise.allSettled(
          imageFiles.map(({ name, srcPath }) =>
            invoke<string>("save_asset", { srcPath, activeFilePath: filePath }).then((relPath) => ({
              name,
              relPath,
            }))
          )
        ).then((results) => {
          const saved = results.flatMap((r) => {
            if (r.status === "fulfilled") return [r.value];
            console.error("save_asset failed:", r.reason);
            return [];
          });
          if (saved.length === 0) return;
          const dropPos = view.posAtCoords({ left: dropX, top: dropY })?.pos;
          if (dropPos === undefined) return;
          // Apply all insertions in one transaction to avoid stale positions
          const tr = view.state.tr;
          let offset = 0;
          for (const { name, relPath } of saved) {
            const node = view.state.schema.nodes.image.create({ src: relPath, alt: name });
            tr.insert(dropPos + offset, node);
            offset += node.nodeSize;
          }
          view.dispatch(tr);
        });
        return true;
      },
    },
    onUpdate({ editor }) {
      // biome-ignore lint/suspicious/noExplicitAny: tiptap-markdown storage has no public type
      const markdown = (editor.storage as any).markdown.getMarkdown() as string;
      onChange?.(markdown);

      if (onWordCount) {
        const text = editor.getText();
        onWordCount(text.trim() ? text.trim().split(/\s+/).length : 0);
      }
    },
    onSelectionUpdate({ editor: ed }) {
      if (!typewriterRef.current || !scrollRef.current) return;
      const { from } = ed.view.state.selection;
      const coords = ed.view.coordsAtPos(from);
      if (coords.top === 0 && coords.bottom === 0) return;
      const scrollEl = scrollRef.current;
      const rect = scrollEl.getBoundingClientRect();
      const cursorRelTop = coords.top - rect.top;
      const target = scrollEl.scrollTop + cursorRelTop - rect.height / 2;
      scrollEl.scrollTo({ top: Math.max(0, target), behavior: "smooth" });
    },
  });

  // Update spellcheck live — set directly on the DOM to avoid replacing editorProps
  useEffect(() => {
    if (!editor) return;
    try {
      editor.view.dom.setAttribute("spellcheck", spellCheck ? "true" : "false");
    } catch {
      // view not yet mounted — initial value is set via editorProps in useEditor
    }
  }, [editor, spellCheck]);

  // Click on the ](url) hint from InlineEditMode → open link dialog
  // Use scrollRef instead of editor.view.dom to avoid accessing the view before it's mounted
  useEffect(() => {
    const container = scrollRef.current;
    if (!container || !editor) return;
    function onMouseDown(e: MouseEvent) {
      const target = e.target as HTMLElement;
      if (!target.classList.contains("link-url-hint")) return;
      e.preventDefault();
      const href = editor.getAttributes("link").href ?? "";
      setLinkDialog({ href });
    }
    container.addEventListener("mousedown", onMouseDown);
    return () => container.removeEventListener("mousedown", onMouseDown);
  }, [editor]);

  // Cmd+K — open link dialog when editor is focused
  useEffect(() => {
    function onKeyDown(e: KeyboardEvent) {
      if (!(e.metaKey || e.ctrlKey) || e.key?.toLowerCase() !== "k") return;
      if (!editor?.isFocused) return;
      e.preventDefault();
      const href = editor.getAttributes("link").href ?? "";
      setLinkDialog({ href });
    }
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [editor]);

  // Cmd+E — toggle inline code; intercept before WKWebView's "Use Selection for Find"
  useEffect(() => {
    function onKeyDown(e: KeyboardEvent) {
      if (!(e.metaKey || e.ctrlKey) || e.key?.toLowerCase() !== "e") return;
      if (!editor?.isFocused) return;
      e.preventDefault();
      editor.chain().focus().toggleCode().run();
    }
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [editor]);

  // Cmd+Shift+V — paste as plain text, stripping all rich formatting
  useEffect(() => {
    function onKeyDown(e: KeyboardEvent) {
      if (!(e.metaKey || e.ctrlKey) || !e.shiftKey || e.key?.toLowerCase() !== "v") return;
      if (!editor?.isFocused) return;
      e.preventDefault();
      navigator.clipboard
        .readText()
        .then((text) => {
          editor.view.dispatch(editor.view.state.tr.insertText(text));
        })
        .catch((err) => {
          console.error("Failed to read clipboard:", err);
        });
    }
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [editor]);

  // Cmd+H — open / close find & replace bar
  useEffect(() => {
    function onKeyDown(e: KeyboardEvent) {
      if (!(e.metaKey || e.ctrlKey) || e.key?.toLowerCase() !== "h") return;
      if (!editor?.isFocused && !showFindReplace) return;
      e.preventDefault();
      setShowFindReplace((v) => {
        if (v) editor?.chain().focus().run();
        return !v;
      });
    }
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [editor, showFindReplace]);

  // Insert / Format menu commands forwarded from the native menu bar
  useEffect(() => {
    let mounted = true;
    let unlisten: (() => void) | undefined;
    listen<string>("menu-action", (event) => {
      if (!editor || linkDialog) return;
      switch (event.payload) {
        case "format-bold":
          editor.chain().focus().toggleBold().run();
          break;
        case "format-italic":
          editor.chain().focus().toggleItalic().run();
          break;
        case "format-strike":
          editor.chain().focus().toggleStrike().run();
          break;
        case "format-code":
          editor.chain().focus().toggleCode().run();
          break;
        case "format-heading-1":
          editor.chain().focus().toggleHeading({ level: 1 }).run();
          break;
        case "format-heading-2":
          editor.chain().focus().toggleHeading({ level: 2 }).run();
          break;
        case "format-heading-3":
          editor.chain().focus().toggleHeading({ level: 3 }).run();
          break;
        case "format-blockquote":
          editor.chain().focus().toggleBlockquote().run();
          break;
        case "format-bullet-list":
          editor.chain().focus().toggleBulletList().run();
          break;
        case "format-ordered-list":
          editor.chain().focus().toggleOrderedList().run();
          break;
        case "insert-link": {
          const href = editor.getAttributes("link").href ?? "";
          setLinkDialog({ href });
          break;
        }
        case "insert-code-block":
          editor.chain().focus().toggleCodeBlock().run();
          break;
        case "insert-hr":
          editor.chain().focus().setHorizontalRule().run();
          break;
        case "insert-table":
          editor.chain().focus().insertTable({ rows: 3, cols: 3, withHeaderRow: true }).run();
          break;
      }
    }).then((fn) => {
      if (mounted) {
        unlisten = fn;
      } else {
        fn();
      }
    });
    return () => {
      mounted = false;
      unlisten?.();
    };
  }, [editor, linkDialog]);

  return (
    <div className="editor-wrapper">
      <div ref={scrollRef} className="editor-scroll">
        <EditorContent editor={editor} />
      </div>
      {editor && showFindReplace && (
        <FindReplaceBar
          editor={editor}
          onClose={() => {
            setShowFindReplace(false);
            editor.chain().focus().run();
          }}
        />
      )}
      {editor && <TableControls editor={editor} />}
      {editor && (
        <BubbleMenu
          editor={editor}
          onLinkClick={() => {
            const href = editor.getAttributes("link").href ?? "";
            setLinkDialog({ href });
          }}
        />
      )}
      {linkDialog && (
        <LinkDialog
          initialHref={linkDialog.href}
          onApply={(url) => {
            editor?.chain().focus().extendMarkRange("link").setLink({ href: url }).run();
            setLinkDialog(null);
          }}
          onRemove={() => {
            editor?.chain().focus().extendMarkRange("link").unsetLink().run();
            setLinkDialog(null);
          }}
          onCancel={() => setLinkDialog(null)}
        />
      )}
    </div>
  );
}

import { listen } from "@tauri-apps/api/event";
import { useEffect, useRef, useState } from "react";
import { CommitDialog } from "./components/CommitDialog";
import { Editor } from "./components/Editor";
import { EmptyState } from "./components/EmptyState";
import { ErrorBoundary } from "./components/ErrorBoundary";
import { FileSwitcher } from "./components/FileSwitcher";
import { NewFileDialog } from "./components/NewFileDialog";
import { PropertiesPanel } from "./components/PropertiesPanel";
import { SearchPanel } from "./components/SearchPanel";
import { Sidebar } from "./components/Sidebar";
import { StatusBar } from "./components/StatusBar";
import { WorkspaceSwitcher } from "./components/WorkspaceSwitcher";
import { resolveImageSrc } from "./lib/imageUtils";
import { useContentTypes } from "./lib/useContentTypes";
import { useEditorPreferences } from "./lib/useEditorPreferences";
import { useFileEditor } from "./lib/useFileEditor";
import { useGit } from "./lib/useGit";
import { useRecentFiles } from "./lib/useRecentFiles";
import { useRecentWorkspaces } from "./lib/useRecentWorkspaces";
import { useTheme } from "./lib/useTheme";
import { useToast } from "./lib/useToast";
import { useWordCountGoal } from "./lib/useWordCountGoal";
import { useWorkspace } from "./lib/useWorkspace";
import "./styles/global.css";
import "./App.css";

type ModalState = { type: "new-file"; dirPath: string; contentType?: string } | null;
type CommitDialogState = { message: string; branch: string } | null;

const SIDEBAR_VISIBLE_KEY = "ovid:sidebarVisible";
const AUTO_REOPEN_KEY = "ovid:skipAutoReopen";

function App() {
  const { resolvedTheme, setPreference } = useTheme();
  const [sidebarVisible, setSidebarVisible] = useState(
    () => localStorage.getItem(SIDEBAR_VISIBLE_KEY) !== "false"
  );
  const [propertiesOpen, setPropertiesOpen] = useState(true);
  const [zenMode, setZenMode] = useState(false);
  const [typewriterMode, setTypewriterMode] = useState(false);
  const [sessionBaseline, setSessionBaseline] = useState<number | null>(null);
  const [baselineCaptured, setBaselineCaptured] = useState(false);
  const [modal, setModal] = useState<ModalState>(null);
  const [switcherOpen, setSwitcherOpen] = useState(false);
  const [workspaceSwitcherOpen, setWorkspaceSwitcherOpen] = useState(false);
  const [searchOpen, setSearchOpen] = useState(false);
  const [commitDialog, setCommitDialog] = useState<CommitDialogState>(null);
  const [coverImageVisible, setCoverImageVisible] = useState(false);

  const { toasts, showToast } = useToast();
  const { prefs, updatePrefs } = useEditorPreferences();
  const { goal: wordCountGoal, setGoal: setWordCountGoal } = useWordCountGoal();

  const {
    selectedFile,
    setSelectedFile,
    fileContent,
    wordCount,
    setWordCount,
    parsedFrontmatter,
    saveStatus,
    selectedPathRef,
    flushPendingSave,
    resetFileState,
    handleCloseFile,
    handleSelectFile,
    handleEditorChange,
    handleFieldChange,
  } = useFileEditor({ showToast });

  const {
    tree,
    workspaceName,
    workspaceRoot,
    workspaceRootPath,
    isAmytisWorkspace,
    assetRoot,
    cdnBase,
    renamingPath,
    setRenamingPath,
    handleOpenWorkspace,
    openWorkspaceAtPath,
    handleNewFile,
    handleRename,
    handleDelete,
  } = useWorkspace({
    showToast,
    flushPendingSave,
    handleCloseFile,
    handleSelectFile,
    selectedFile,
    selectedPathRef,
    setSelectedFile,
    resetFileState,
  });

  const { recentFiles, pushRecent, resetRecent } = useRecentFiles(workspaceRoot);
  const { recentWorkspaces, pushRecentWorkspace } = useRecentWorkspaces();
  const { gitStatusMap, isGitRepo, refreshGitStatus, handleCommit, getBranch } =
    useGit(workspaceRoot);
  const contentTypes = useContentTypes(workspaceRoot, isAmytisWorkspace);

  // Sync recent files list when workspace changes
  useEffect(() => {
    if (workspaceRoot) resetRecent(workspaceRoot);
  }, [workspaceRoot, resetRecent]);

  // Track recently opened workspaces
  useEffect(() => {
    if (workspaceRootPath && workspaceName) {
      pushRecentWorkspace(workspaceRootPath, workspaceName);
    }
  }, [workspaceRootPath, workspaceName, pushRecentWorkspace]);

  // Auto-reopen last workspace on launch (once)
  const autoReopenAttempted = useRef(false);
  useEffect(() => {
    if (
      autoReopenAttempted.current ||
      workspaceRootPath !== null ||
      recentWorkspaces.length === 0 ||
      localStorage.getItem(AUTO_REOPEN_KEY) === "true"
    )
      return;
    autoReopenAttempted.current = true;
    void openWorkspaceAtPath(recentWorkspaces[0].rootPath);
  }, [recentWorkspaces, openWorkspaceAtPath, workspaceRootPath]);

  // Reset per-file UI state when switching files (selectedFile is the trigger, not used in body)
  // biome-ignore lint/correctness/useExhaustiveDependencies: selectedFile is the intended trigger
  useEffect(() => {
    setSessionBaseline(null);
    setBaselineCaptured(false);
    setCoverImageVisible(false);
  }, [selectedFile]);

  // Capture baseline on first word-count event for the new file (including empty files)
  useEffect(() => {
    if (!baselineCaptured) {
      setSessionBaseline(wordCount);
      setBaselineCaptured(true);
    }
  }, [wordCount, baselineCaptured]);

  // Global keyboard shortcuts
  useEffect(() => {
    function onKeyDown(e: KeyboardEvent) {
      // Escape exits zen mode (before other guards)
      if (
        e.key === "Escape" &&
        zenMode &&
        !modal &&
        !commitDialog &&
        !switcherOpen &&
        !workspaceSwitcherOpen
      ) {
        setZenMode(false);
        return;
      }
      if (!e.metaKey && !e.ctrlKey) return;
      // Ctrl+Cmd+Z — zen mode (macOS); avoids conflict with Redo (Cmd+Shift+Z)
      if (e.metaKey && e.ctrlKey && e.key === "z") {
        e.preventDefault();
        setZenMode((v) => !v);
        return;
      }
      // Mode toggles work even when editor has focus
      if (e.shiftKey && e.key === "P") {
        e.preventDefault();
        setPropertiesOpen((v) => !v);
        return;
      }
      const target = e.target as HTMLElement;
      if (
        target instanceof HTMLInputElement ||
        target instanceof HTMLTextAreaElement ||
        target.isContentEditable
      )
        return;
      switch (e.key) {
        case "\\":
          e.preventDefault();
          setSidebarVisible((v) => {
            const next = !v;
            localStorage.setItem(SIDEBAR_VISIBLE_KEY, String(next));
            return next;
          });
          break;
        case "o":
          e.preventDefault();
          if (e.shiftKey) {
            setWorkspaceSwitcherOpen(true);
          } else {
            void handleOpenWorkspace();
          }
          break;
        case "F":
          if (e.shiftKey) {
            e.preventDefault();
            if (workspaceRoot) setSearchOpen((v) => !v);
          }
          break;
        case "G":
          if (e.shiftKey && isGitRepo) {
            e.preventDefault();
            void getBranch()
              .then((branch) => {
                const title = parsedFrontmatter.title ?? selectedFile?.name ?? "";
                setCommitDialog({ message: `Update: ${title}`, branch });
              })
              .catch(() => showToast("Failed to get git branch"));
          }
          break;
        case "p":
          e.preventDefault();
          if (tree.length > 0) setSwitcherOpen(true);
          break;
        case "n":
          e.preventDefault();
          if (workspaceRoot)
            setModal({ type: "new-file", dirPath: workspaceRoot, contentType: "post" });
          break;
        case "s":
          e.preventDefault();
          void flushPendingSave();
          break;
        case "w":
          e.preventDefault();
          void handleCloseFile();
          break;
      }
    }
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [
    flushPendingSave,
    handleCloseFile,
    handleOpenWorkspace,
    workspaceRoot,
    tree,
    isGitRepo,
    getBranch,
    parsedFrontmatter,
    selectedFile,
    showToast,
    zenMode,
    modal,
    commitDialog,
    switcherOpen,
    workspaceSwitcherOpen,
  ]);

  // Refresh git status after each save completes
  useEffect(() => {
    if (saveStatus === "saved" && isGitRepo) void refreshGitStatus();
  }, [saveStatus, isGitRepo, refreshGitStatus]);

  // Forward native menu events to the same handlers as keyboard shortcuts
  useEffect(() => {
    let mounted = true;
    let unlisten: (() => void) | undefined;
    listen<string>("menu-action", (event) => {
      const hasBlockingOverlay =
        modal !== null || commitDialog !== null || switcherOpen || workspaceSwitcherOpen;
      switch (event.payload) {
        case "new-post":
        case "new-flow":
        case "new-note":
        case "new-series":
        case "new-book":
        case "new-page":
          if (!hasBlockingOverlay && workspaceRoot)
            setModal({
              type: "new-file",
              dirPath: workspaceRoot,
              contentType: event.payload.replace("new-", ""),
            });
          break;
        case "open-workspace":
          void handleOpenWorkspace();
          break;
        case "switch-workspace":
          if (!hasBlockingOverlay) setWorkspaceSwitcherOpen(true);
          break;
        case "save":
          void flushPendingSave();
          break;
        case "close-file":
          void handleCloseFile();
          break;
        case "toggle-sidebar":
          setSidebarVisible((v) => {
            const next = !v;
            localStorage.setItem(SIDEBAR_VISIBLE_KEY, String(next));
            return next;
          });
          break;
        case "toggle-properties":
          setPropertiesOpen((v) => !v);
          break;
        case "toggle-search":
          if (workspaceRoot) setSearchOpen((v) => !v);
          break;
        case "zen-mode":
          setZenMode((v) => !v);
          break;
        case "typewriter-mode":
          setTypewriterMode((v) => !v);
          break;
        case "file-switcher":
          if (!hasBlockingOverlay && tree.length > 0) setSwitcherOpen(true);
          break;
        case "toggle-spell-check":
          updatePrefs({ spellCheck: !prefs.spellCheck });
          break;
        case "commit-push":
          if (!hasBlockingOverlay && isGitRepo) {
            void getBranch()
              .then((branch) => {
                const title = parsedFrontmatter.title ?? selectedFile?.name ?? "";
                setCommitDialog({ message: `Update: ${title}`, branch });
              })
              .catch(() => showToast("Failed to get git branch"));
          }
          break;
      }
    }).then((fn) => {
      if (mounted) {
        unlisten = fn;
      } else {
        fn();
      }
    });
    return () => {
      mounted = false;
      unlisten?.();
    };
  }, [
    modal,
    commitDialog,
    switcherOpen,
    workspaceSwitcherOpen,
    workspaceRoot,
    tree,
    isGitRepo,
    getBranch,
    parsedFrontmatter,
    selectedFile,
    showToast,
    flushPendingSave,
    handleCloseFile,
    handleOpenWorkspace,
    prefs,
    updatePrefs,
  ]);

  const hasFrontmatter = Object.keys(parsedFrontmatter).length > 0;
  const coverImagePath =
    parsedFrontmatter.coverImage !== undefined ? String(parsedFrontmatter.coverImage) : undefined;

  async function handlePublishAwareFieldChange(key: string, value: unknown) {
    await handleFieldChange(key, value as Parameters<typeof handleFieldChange>[1]);
    if (key === "draft" && value === false && isGitRepo) {
      try {
        const branch = await getBranch();
        const title = parsedFrontmatter.title ?? selectedFile?.name ?? "";
        setCommitDialog({ message: `Publish: ${title}`, branch });
      } catch {
        // git unavailable — ignore
      }
    }
  }

  function handleOpenByPath(path: string) {
    const node = tree
      .flatMap(function flatten(n): typeof tree {
        return n.isDirectory ? (n.children ?? []).flatMap(flatten) : [n];
      })
      .find((n) => n.path === path);
    if (node) {
      void handleSelectFile(node);
      pushRecent(node);
      setSearchOpen(false);
    }
  }

  const sessionWordsAdded = sessionBaseline !== null ? Math.max(0, wordCount - sessionBaseline) : 0;

  return (
    <div className="app" data-zen={zenMode ? "true" : undefined}>
      <div className="app-body">
        {searchOpen ? (
          <SearchPanel onOpenFile={handleOpenByPath} onClose={() => setSearchOpen(false)} />
        ) : (
          <Sidebar
            tree={tree}
            selectedPath={selectedFile?.path ?? null}
            renamingPath={renamingPath}
            visible={sidebarVisible}
            workspaceName={workspaceName}
            gitStatusMap={gitStatusMap}
            onSelect={(node) => {
              void handleSelectFile(node);
              if (!node.isDirectory) pushRecent(node);
            }}
            onOpenWorkspace={handleOpenWorkspace}
            onOpenSwitcher={() => setWorkspaceSwitcherOpen(true)}
            onNewFile={(dirPath) => setModal({ type: "new-file", dirPath })}
            onRename={handleRename}
            onDelete={handleDelete}
            onStartRename={setRenamingPath}
            onCancelRename={() => setRenamingPath(null)}
          />
        )}
        <div className="editor-column">
          {selectedFile && coverImageVisible && coverImagePath && (
            <div className="cover-image-banner">
              <img
                src={resolveImageSrc(coverImagePath, selectedFile.path, assetRoot, cdnBase)}
                alt=""
              />
            </div>
          )}
          {selectedFile ? (
            <ErrorBoundary key={selectedFile.path}>
              <Editor
                key={selectedFile.path}
                content={fileContent}
                filePath={selectedFile.path}
                workspaceRootPath={assetRoot}
                cdnBase={cdnBase}
                typewriterMode={typewriterMode}
                spellCheck={prefs.spellCheck}
                onWordCount={setWordCount}
                onChange={handleEditorChange}
              />
            </ErrorBoundary>
          ) : (
            <EmptyState
              workspaceOpen={workspaceRoot !== null}
              recentFiles={recentFiles}
              onOpenWorkspace={handleOpenWorkspace}
              onOpenRecent={handleOpenByPath}
            />
          )}
        </div>
        {selectedFile && hasFrontmatter && (
          <PropertiesPanel
            frontmatter={parsedFrontmatter}
            visible={propertiesOpen}
            slug={selectedFile.name.replace(/\.mdx?$/, "")}
            coverImageVisible={coverImageVisible}
            onFieldChange={handlePublishAwareFieldChange}
            onToggleCoverImage={() => setCoverImageVisible((v) => !v)}
          />
        )}
      </div>
      <StatusBar
        fileName={selectedFile?.name ?? null}
        wordCount={wordCount}
        resolvedTheme={resolvedTheme}
        saveStatus={saveStatus}
        zenMode={zenMode}
        typewriterMode={typewriterMode}
        sessionWordsAdded={sessionWordsAdded}
        wordCountGoal={wordCountGoal}
        fontFamily={prefs.fontFamily}
        fontSize={prefs.fontSize}
        spellCheck={prefs.spellCheck}
        onToggleTheme={() => setPreference(resolvedTheme === "dark" ? "light" : "dark")}
        onToggleZen={() => setZenMode((v) => !v)}
        onToggleTypewriter={() => setTypewriterMode((v) => !v)}
        onSetFontFamily={(f) => updatePrefs({ fontFamily: f })}
        onSetFontSize={(s) => updatePrefs({ fontSize: s })}
        onToggleSpellCheck={() => updatePrefs({ spellCheck: !prefs.spellCheck })}
        onSetWordCountGoal={setWordCountGoal}
      />
      {toasts.length > 0 && (
        <div className="toast-container">
          {toasts.map((t) => (
            <div key={t.id} className="toast">
              {t.message}
            </div>
          ))}
        </div>
      )}
      {workspaceSwitcherOpen && (
        <WorkspaceSwitcher
          recentWorkspaces={recentWorkspaces}
          currentRootPath={workspaceRootPath}
          onSelect={(rootPath) => void openWorkspaceAtPath(rootPath)}
          onOpenOther={handleOpenWorkspace}
          onClose={() => setWorkspaceSwitcherOpen(false)}
        />
      )}
      {switcherOpen && (
        <FileSwitcher
          tree={tree}
          recentFiles={recentFiles}
          onSelect={(node) => {
            void handleSelectFile(node);
            pushRecent(node);
            setSwitcherOpen(false);
          }}
          onClose={() => setSwitcherOpen(false)}
        />
      )}
      {modal?.type === "new-file" && (
        <NewFileDialog
          contentTypes={contentTypes}
          preselectedType={modal.contentType}
          onConfirm={(name, contentType) => {
            void handleNewFile(modal.dirPath, name, contentType);
            setModal(null);
          }}
          onCancel={() => setModal(null)}
        />
      )}
      {commitDialog && (
        <CommitDialog
          defaultMessage={commitDialog.message}
          branch={commitDialog.branch}
          onCommit={(message, push) => {
            void flushPendingSave()
              .then(() => handleCommit(message, push))
              .then(() => setCommitDialog(null))
              .catch((err) => showToast(`Commit failed: ${err}`));
          }}
          onCancel={() => setCommitDialog(null)}
        />
      )}
    </div>
  );
}

export default App;

