/* ── Right-side properties panel ─────────────── */
.properties-panel {
  width: 220px;
  min-width: 220px;
  background: var(--color-surface-subtle);
  border-left: 1px solid var(--color-border);
  display: flex;
  flex-direction: column;
  overflow-y: auto;
  overflow-x: hidden;
  user-select: none;
  transition:
    width 0.2s ease,
    min-width 0.2s ease,
    border-left-color 0.2s ease;
}

.properties-panel.hidden {
  width: 0;
  min-width: 0;
  border-left-color: transparent;
  visibility: hidden;
}

/* ── Header: type + status badge ─────────────── */
.prop-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 14px 10px;
  border-bottom: 1px solid var(--color-border);
  gap: 8px;
}

.prop-status-badge {
  flex-shrink: 0;
  font-size: 10px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  padding: 2px 7px;
  border-radius: 4px;
  cursor: pointer;
  color: var(--color-warning);
  background: var(--color-warning-subtle);
  transition:
    color 0.15s,
    background 0.15s,
    opacity 0.15s;
}

.prop-status-badge:hover {
  opacity: 0.8;
}

.prop-status-badge.published {
  color: var(--color-accent);
  background: var(--color-accent-subtle);
}

/* ── Body ────────────────────────────────────── */
.properties-body {
  padding: 14px 14px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

/* ── Individual field ────────────────────────── */
.prop-field {
  display: flex;
  flex-direction: column;
  gap: 3px;
}

.prop-label {
  font-size: 10px;
  font-weight: 600;
  color: var(--color-fg-subtle);
  text-transform: uppercase;
  letter-spacing: 0.07em;
}

.prop-value {
  font-size: 13px;
  color: var(--color-fg-muted);
  line-height: 1.4;
  overflow-wrap: anywhere;
  word-wrap: break-word;
}

/* ── Slug (read-only) ────────────────────────── */
.prop-slug {
  font-size: 12px;
  color: var(--color-fg-subtle);
  font-family: var(--font-mono, monospace);
  word-break: break-all;
  padding: 2px 0;
}

/* ── Editable areas ──────────────────────────── */
.prop-editable-area {
  display: block;
  width: 100%;
  text-align: left;
  padding: 3px 6px;
  margin: 0 -6px;
  border-radius: 4px;
  cursor: text;
  transition: background 0.15s;
  box-sizing: content-box;
}

.prop-editable-area:hover {
  background: var(--color-surface-hover);
}

