 17	interface UseWorkspaceOptions {
 18	  showToast: (msg: string) => void;
 19	  flushPendingSave: () => Promise<void>;
 20	  handleCloseFile: () => Promise<void>;
 21	  handleSelectFile: (node: FileNode) => Promise<void>;
 22	  selectedFile: FileNode | null;
 23	  selectedPathRef: MutableRefObject<string | null>;
 24	  setSelectedFile: (node: FileNode | null) => void;
 25	  resetFileState: () => void;
 26	}
