 28	function findNode(nodes: FileNode[], path: string): FileNode | undefined {
 29	  for (const n of nodes) {
 30	    if (n.path === path) return n;
 31	    if (n.children) {
 32	      const found = findNode(n.children, path);
 33	      if (found) return found;
 34	    }
 35	  }
 36	}
