 38	export function useWorkspace({
 39	  showToast,
 40	  flushPendingSave,
 41	  handleCloseFile,
 42	  handleSelectFile,
 43	  selectedFile,
 44	  selectedPathRef,
 45	  setSelectedFile,
 46	  resetFileState,
 47	}: UseWorkspaceOptions) {
 48	  const [tree, setTree] = useState<FileNode[]>([]);
 49	  const [workspaceName, setWorkspaceName] = useState<string | null>(null);
 50	  const [workspaceRoot, setWorkspaceRoot] = useState<string | null>(null);
 51	  const [workspaceRootPath, setWorkspaceRootPath] = useState<string | null>(null);
 52	  const [isAmytisWorkspace, setIsAmytisWorkspace] = useState(false);
 53	  const [assetRoot, setAssetRoot] = useState<string | undefined>(undefined);
 54	  const [cdnBase, setCdnBase] = useState<string | undefined>(undefined);
 55	  const [renamingPath, setRenamingPath] = useState<string | null>(null);
 56	
 57	  const refreshTree = useCallback(async (): Promise<FileNode[]> => {
 58	    try {
 59	      const updated = await invoke<FileNode[]>("list_workspace");
 60	      setTree(updated);
 61	      return updated;
 62	    } catch (err) {
 63	      console.error("Failed to refresh tree:", err);
 64	      return [];
 65	    }
 66	  }, []);
 67	
 68	  const applyWorkspaceResult = useCallback(
 69	    (result: WorkspaceResult) => {
 70	      setTree(result.tree);
 71	      setWorkspaceName(result.name);
 72	      setWorkspaceRoot(result.treeRoot);
 73	      setWorkspaceRootPath(result.rootPath);
 74	      setIsAmytisWorkspace(result.isAmytisWorkspace);
 75	      setAssetRoot(result.assetRoot);
 76	      setCdnBase(result.cdnBase ?? undefined);
 77	      resetFileState();
 78	      if (!result.isAmytisWorkspace) {
 79	        showToast("This folder doesn't look like an Amytis workspace.");
 80	      }
 81	    },
 82	    [resetFileState, showToast]
 83	  );
 84	
 85	  const openWorkspaceAtPath = useCallback(
 86	    async (path: string) => {
 87	      await flushPendingSave();
 88	      try {
 89	        const result = await invoke<WorkspaceResult | null>("open_workspace_at_path", { path });
 90	        if (result) applyWorkspaceResult(result);
 91	        else showToast("Could not open workspace — path may no longer be valid.");
 92	      } catch (err) {
 93	        console.error("Failed to open workspace:", err);
 94	        showToast(`Failed to open workspace: ${err}`);
 95	      }
 96	    },
 97	    [flushPendingSave, showToast, applyWorkspaceResult]
 98	  );
 99	
100	  const handleOpenWorkspace = useCallback(async () => {
101	    await flushPendingSave();
102	    try {
103	      const result = await invoke<WorkspaceResult | null>("open_workspace");
104	      if (result) applyWorkspaceResult(result);
105	    } catch (err) {
106	      console.error("Failed to open workspace:", err);
107	      showToast(`Failed to open workspace: ${err}`);
108	    }
109	  }, [flushPendingSave, showToast, applyWorkspaceResult]);
110	
111	  async function handleNewFile(dirPath: string, filename: string, contentType?: string) {
112	    const slug = filename.replace(/\.md$/, "");
113	    const filePath = `${dirPath}/${slug}.md`;
114	    const content = contentType
115	      ? createTypedFrontmatter(slug, contentType)
116	      : createAmytisFrontmatter(slug);
117	    try {
118	      await invoke("create_file", { path: filePath, content });
119	      const updated = await refreshTree();
120	      const newNode = findNode(updated, filePath);
121	      if (newNode) await handleSelectFile(newNode);
122	    } catch (err) {
123	      console.error("Failed to create file:", err);
124	      showToast(`Failed to create file: ${err}`);
125	    }
126	  }
127	
128	  async function handleRename(node: FileNode, newName: string) {
129	    setRenamingPath(null);
130	    await flushPendingSave();
131	    const dir = node.path.substring(0, node.path.lastIndexOf("/"));
132	    const ext = node.extension ?? ".md";
133	    const newPath = `${dir}/${newName}${newName.endsWith(ext) ? "" : ext}`;
134	    try {
135	      await invoke("rename_file", { oldPath: node.path, newPath });
136	      const updated = await refreshTree();
137	      if (selectedFile?.path === node.path) {
138	        const renamed = findNode(updated, newPath);
139	        if (renamed) {
140	          selectedPathRef.current = newPath;
141	          setSelectedFile(renamed);
142	        }
143	      }
144	    } catch (err) {
145	      console.error("Failed to rename file:", err);
146	      showToast(`Failed to rename: ${err}`);
147	    }
148	  }
149	
150	  async function handleDelete(node: FileNode) {
151	    const confirmed = window.confirm(`Move "${node.name}" to Trash?`);
152	    if (!confirmed) return;
153	    if (selectedFile?.path === node.path) {
154	      await flushPendingSave();
155	    }
156	    try {
157	      await invoke("trash_file", { path: node.path });
158	      if (selectedFile?.path === node.path) await handleCloseFile();
159	      await refreshTree();
160	    } catch (err) {
161	      console.error("Failed to delete file:", err);
162	      showToast(`Failed to delete: ${err}`);
163	    }
164	  }
165	
166	  return {
167	    tree,
168	    workspaceName,
169	    workspaceRoot,
170	    workspaceRootPath,
171	    isAmytisWorkspace,
172	    assetRoot,
173	    cdnBase,
174	    renamingPath,
175	    setRenamingPath,
176	    handleOpenWorkspace,
177	    openWorkspaceAtPath,
178	    handleNewFile,
179	    handleRename,
180	    handleDelete,
181	  };
182	}

