/// Compute the asset-serving root and CDN base for a workspace.
/// `asset_root` is `<workspace>/public/` when that directory exists (static-site
/// convention), falling back to the workspace root itself.
fn derive_workspace_meta(root: &Path, is_amytis_workspace: bool) -> (PathBuf, Option<String>) {
    let pub_dir = root.join("public");
    let asset_root = if pub_dir.is_dir() { pub_dir } else { root.to_path_buf() };
    let cdn_base = if is_amytis_workspace {
        parse_cdn_base(&root.join("site.config.ts"))
    } else {
        None
    };
    (asset_root, cdn_base)
}

#[tauri::command]
async fn open_workspace_at_path(
    path: String,
    app: tauri::AppHandle,
    state: State<'_, WorkspaceState>,
) -> Result<Option<WorkspaceResult>, String> {
    let root = PathBuf::from(&path);
    if !root.is_dir() {
        return Ok(None);
    }

    let name = root
        .file_name()
        .map(|n| n.to_string_lossy().to_string())
        .unwrap_or_else(|| root.to_string_lossy().to_string());

    let content_dir = root.join("content");
    let tree_root = if content_dir.is_dir() { content_dir } else { root.clone() };

    *state.tree_root.lock().map_err(|e| e.to_string())? = Some(tree_root.clone());
    *state.workspace_root.lock().map_err(|e| e.to_string())? = Some(root.clone());

    let is_amytis_workspace = root.join("site.config.ts").is_file() && root.join("content").is_dir();
    let tree = walk_dir(&tree_root);
    let (asset_root, cdn_base) = derive_workspace_meta(&root, is_amytis_workspace);

    // Grant asset protocol access to the entire workspace root so that both
    // root-relative paths (resolved inside public/) and relative paths
    // (resolved anywhere within the workspace) can be served.
    let _ = app.asset_protocol_scope().allow_directory(&root, true);

    Ok(Some(WorkspaceResult {
        name,
        root_path: root.to_string_lossy().to_string(),
        tree_root: tree_root.to_string_lossy().to_string(),
        asset_root: asset_root.to_string_lossy().to_string(),
        tree,
        is_amytis_workspace,
        cdn_base,
    }))
}

#[tauri::command]
async fn open_workspace(
    app: tauri::AppHandle,
    state: State<'_, WorkspaceState>,
) -> Result<Option<WorkspaceResult>, String> {
    let (tx, rx) = tokio::sync::oneshot::channel::<Option<tauri_plugin_dialog::FilePath>>();
    app.dialog().file().pick_folder(move |folder| {
        tx.send(folder).ok();
    });
    let folder = match rx.await.ok().flatten() {
        Some(f) => f,
        None => return Ok(None),
    };
    let root: PathBuf = match folder {
        tauri_plugin_dialog::FilePath::Path(p) => p,
        tauri_plugin_dialog::FilePath::Url(u) => PathBuf::from(u.path()),
    };

    let name = root
        .file_name()
        .map(|n| n.to_string_lossy().to_string())
        .unwrap_or_else(|| root.to_string_lossy().to_string());

    // Prefer content/ subdirectory for Amytis workspaces
    let content_dir = root.join("content");
    let tree_root = if content_dir.is_dir() {
        content_dir
    } else {
        root.clone()
    };

    // Store roots for path validation and git/config commands
    *state.tree_root.lock().map_err(|e| e.to_string())? = Some(tree_root.clone());
    *state.workspace_root.lock().map_err(|e| e.to_string())? = Some(root.clone());

    let is_amytis_workspace = root.join("site.config.ts").is_file() && root.join("content").is_dir();
    let tree = walk_dir(&tree_root);
    let (asset_root, cdn_base) = derive_workspace_meta(&root, is_amytis_workspace);

    // Grant asset protocol access to the entire workspace root so that both
    // root-relative paths (resolved inside public/) and relative paths
    // (resolved anywhere within the workspace) can be served.
    let _ = app.asset_protocol_scope().allow_directory(&root, true);

    Ok(Some(WorkspaceResult {
        name,
        root_path: root.to_string_lossy().to_string(),
        tree_root: tree_root.to_string_lossy().to_string(),
        asset_root: asset_root.to_string_lossy().to_string(),
        tree,
        is_amytis_workspace,
        cdn_base,
    }))
}

