     8→import { Table } from "@tiptap/extension-table";
     9→import { TableCell } from "@tiptap/extension-table-cell";
    10→import { TableHeader } from "@tiptap/extension-table-header";
    11→import { TableRow } from "@tiptap/extension-table-row";
    12→import Typography from "@tiptap/extension-typography";
    13→import { EditorContent, ReactNodeViewRenderer, useEditor } from "@tiptap/react";
    14→import StarterKit from "@tiptap/starter-kit";
    15→import { common, createLowlight } from "lowlight";
    16→import { useEffect, useRef, useState } from "react";
    17→import { Markdown } from "tiptap-markdown";
    18→import { FindReplace } from "../lib/tiptap/FindReplace";
    19→import { ImageRenderer } from "../lib/tiptap/ImageRenderer";
    20→import { InlineEditMode } from "../lib/tiptap/InlineEditMode";
    21→import { LinkPreview } from "../lib/tiptap/LinkPreview";
    22→import { TextFolding } from "../lib/tiptap/TextFolding";
    23→import { BubbleMenu } from "./BubbleMenu";
    24→import { CodeBlockView } from "./CodeBlockView";
    25→import { FindReplaceBar } from "./FindReplaceBar";
    26→import { LinkDialog } from "./LinkDialog";
    27→import { TableControls } from "./TableControls";
    28→import "katex/dist/katex.min.css";
    29→import "../styles/editor.css";
    30→
    31→const lowlight = createLowlight(common);
    32→
    33→const IMAGE_MIME = /^image\/(png|jpe?g|gif|webp|avif|svg\+xml)$/;
    34→
    35→interface EditorProps {
    36→  content?: string;
    37→  filePath?: string;
    38→  assetRoot?: string;
    39→  cdnBase?: string;
    40→  typewriterMode?: boolean;
    41→  spellCheck?: boolean;
    42→  onWordCount?: (count: number) => void;
    43→  onChange?: (markdown: string) => void;
    44→}
    45→
    46→export function Editor({
    47→  content = "",
    48→  filePath,
    49→  assetRoot,
    50→  cdnBase,
    51→  typewriterMode = false,
    52→  spellCheck = true,
    53→  onWordCount,
    54→  onChange,
    55→}: EditorProps) {
    56→  const scrollRef = useRef<HTMLDivElement>(null);
    57→  const typewriterRef = useRef(typewriterMode);
    58→  useEffect(() => {
    59→    typewriterRef.current = typewriterMode;
    60→  }, [typewriterMode]);
    61→
    62→  const [linkDialog, setLinkDialog] = useState<{ href: string } | null>(null);
    63→  const [showFindReplace, setShowFindReplace] = useState(false);
    64→
    65→  const editor = useEditor({
    66→    extensions: [
    67→      StarterKit.configure({ codeBlock: false }),
    68→      CodeBlockLowlight.extend({
    69→        addNodeView() {
    70→          return ReactNodeViewRenderer(CodeBlockView);
    71→        },
    72→      }).configure({ lowlight }),
    73→      Markdown.configure({
    74→        transformPastedText: true,
    75→        transformCopiedText: true,
    76→      }),
    77→      Placeholder.configure({
    78→        placeholder: "Start writing…",
    79→      }),
    80→      Typography,
    81→      Link.extend({
    82→        addInputRules() {
    83→          return [
    84→            new InputRule({
    85→              // Match completed [text](url) at the cursor
    86→              find: /\[([^[\]]+)\]\(([^()]+)\)$/,
    87→              handler: ({ range, match, chain }) => {
    88→                const [, text, href] = match;
    89→                chain()
    90→                  .deleteRange(range)
    91→                  .insertContentAt(range.from, {
    92→                    type: "text",
    93→                    text,
    94→                    marks: [{ type: "link", attrs: { href, rel: "noopener noreferrer" } }],
    95→                  })
    96→                  .run();
    97→              },
    98→            }),
    99→          ];
   100→        },
   101→      }).configure({
   102→        openOnClick: false,
   103→        HTMLAttributes: { rel: "noopener noreferrer" },
   104→      }),
   105→      ImageRenderer.configure({ filePath, assetRoot, cdnBase }),
   106→      Table.configure({ resizable: true }),
   107→      TableRow,
   108→      TableHeader,
   109→      TableCell,
   110→      Mathematics,
   111→      LinkPreview,
   112→      FindReplace,
   113→      TextFolding,
   114→      InlineEditMode,
   115→    ],
   116→    content,
   117→    editorProps: {
   118→      attributes: { spellcheck: spellCheck ? "true" : "false" },
   119→      handlePaste(view, event) {
   120→        const text = (event.clipboardData?.getData("text/plain") ?? "").trim();
   121→        if (!/^https?:\/\/\S+$/.test(text)) return false;
   122→        if (view.state.selection.empty) return false;
   123→        // Paste a URL with text selected → apply it as a link mark
   124→        event.preventDefault();
   125→        const { from, to } = view.state.selection;
   126→        const linkMark = view.state.schema.marks.link.create({
   127→          href: text,
   128→          rel: "noopener noreferrer",
   129→        });
   130→        view.dispatch(view.state.tr.addMark(from, to, linkMark));
   131→        return true;
   132→      },
   133→      handleDrop(view, event) {
   134→        const imageFiles = Array.from(event.dataTransfer?.files ?? [])
   135→          .filter((f) => IMAGE_MIME.test(f.type))
   136→          .map((f) => ({ name: f.name, srcPath: (f as { path?: string }).path }))
   137→          .filter((f): f is { name: string; srcPath: string } => f.srcPath !== undefined);
   138→        if (imageFiles.length === 0) return false;
   139→        event.preventDefault();
   140→        // Capture coords now; recompute position after async uploads settle
   141→        // to avoid using a stale absolute offset if the document changes.
   142→        const dropX = event.clientX;
   143→        const dropY = event.clientY;
   144→        Promise.allSettled(
   145→          imageFiles.map(({ name, srcPath }) =>
   146→            invoke<string>("save_asset", { srcPath, activeFilePath: filePath }).then((relPath) => ({
   147→              name,
   148→              relPath,
   149→            }))
   150→          )
   151→        ).then((results) => {
   152→          const saved = results.flatMap((r) => {
   153→            if (r.status === "fulfilled") return [r.value];
   154→            console.error("save_asset failed:", r.reason);
   155→            return [];
   156→          });
   157→          if (saved.length === 0) return;
   158→          const dropPos = view.posAtCoords({ left: dropX, top: dropY })?.pos;
   159→          if (dropPos === undefined) return;
   160→          // Apply all insertions in one transaction to avoid stale positions
   161→          const tr = view.state.tr;
   162→          let offset = 0;
   163→          for (const { name, relPath } of saved) {
   164→            const node = view.state.schema.nodes.image.create({ src: relPath, alt: name });
   165→            tr.insert(dropPos + offset, node);
   166→            offset += node.nodeSize;
   167→          }
   168→          view.dispatch(tr);
   169→        });
   170→        return true;
   171→      },
   172→    },
   173→    onUpdate({ editor }) {
   174→      // biome-ignore lint/suspicious/noExplicitAny: tiptap-markdown storage has no public type
   175→      const markdown = (editor.storage as any).markdown.getMarkdown() as string;
   176→      onChange?.(markdown);
   177→
   178→      if (onWordCount) {
   179→        const text = editor.getText();
   180→        onWordCount(text.trim() ? text.trim().split(/\s+/).length : 0);
   181→      }
   182→    },
   183→    onSelectionUpdate({ editor: ed }) {
   184→      if (!typewriterRef.current || !scrollRef.current) return;
   185→      const { from } = ed.view.state.selection;
   186→      const coords = ed.view.coordsAtPos(from);
   187→      if (coords.top === 0 && coords.bottom === 0) return;
   188→      const scrollEl = scrollRef.current;
   189→      const rect = scrollEl.getBoundingClientRect();
   190→      const cursorRelTop = coords.top - rect.top;
   191→      const target = scrollEl.scrollTop + cursorRelTop - rect.height / 2;
   192→      scrollEl.scrollTo({ top: Math.max(0, target), behavior: "smooth" });
   193→    },
   194→  });
   195→
   196→  // Update spellcheck live — set directly on the DOM to avoid replacing editorProps
   197→  useEffect(() => {
   198→    if (!editor) return;
   199→    try {
   200→      editor.view.dom.setAttribute("spellcheck", spellCheck ? "true" : "false");
   201→    } catch {
   202→      // view not yet mounted — initial value is set via editorProps in useEditor
   203→    }
   204→  }, [editor, spellCheck]);
   205→
   206→  // Click on the ](url) hint from InlineEditMode → open link dialog
   207→  // Use scrollRef instead of editor.view.dom to avoid accessing the view before it's mounted
   208→  useEffect(() => {
   209→    const container = scrollRef.current;
   210→    if (!container || !editor) return;
   211→    function onMouseDown(e: MouseEvent) {
   212→      const target = e.target as HTMLElement;
   213→      if (!target.classList.contains("link-url-hint")) return;
   214→      e.preventDefault();
   215→      const href = editor.getAttributes("link").href ?? "";
   216→      setLinkDialog({ href });
   217→    }
   218→    container.addEventListener("mousedown", onMouseDown);
   219→    return () => container.removeEventListener("mousedown", onMouseDown);
   220→  }, [editor]);
   221→
   222→  // Cmd+K — open link dialog when editor is focused
   223→  useEffect(() => {
   224→    function onKeyDown(e: KeyboardEvent) {
   225→      if (!(e.metaKey || e.ctrlKey) || e.key?.toLowerCase() !== "k") return;
   226→      if (!editor?.isFocused) return;
   227→      e.preventDefault();
   228→      const href = editor.getAttributes("link").href ?? "";
   229→      setLinkDialog({ href });
   230→    }
   231→    window.addEventListener("keydown", onKeyDown);
   232→    return () => window.removeEventListener("keydown", onKeyDown);
   233→  }, [editor]);
   234→
   235→  // Cmd+E — toggle inline code; intercept before WKWebView's "Use Selection for Find"
   236→  useEffect(() => {
   237→    function onKeyDown(e: KeyboardEvent) {
   238→      if (!(e.metaKey || e.ctrlKey) || e.key?.toLowerCase() !== "e") return;
   239→      if (!editor?.isFocused) return;
   240→      e.preventDefault();
   241→      editor.chain().focus().toggleCode().run();
   242→    }
   243→    window.addEventListener("keydown", onKeyDown);
   244→    return () => window.removeEventListener("keydown", onKeyDown);
   245→  }, [editor]);
   246→
   247→  // Cmd+Shift+V — paste as plain text, stripping all rich formatting
   248→  useEffect(() => {
   249→    function onKeyDown(e: KeyboardEvent) {
   250→      if (!(e.metaKey || e.ctrlKey) || !e.shiftKey || e.key?.toLowerCase() !== "v") return;
   251→      if (!editor?.isFocused) return;
   252→      e.preventDefault();
   253→      navigator.clipboard
   254→        .readText()
   255→        .then((text) => {
   256→          editor.view.dispatch(editor.view.state.tr.insertText(text));
   257→        })
   258→        .catch((err) => {
   259→          console.error("Failed to read clipboard:", err);
   260→        });
   261→    }
   262→    window.addEventListener("keydown", onKeyDown);
   263→    return () => window.removeEventListener("keydown", onKeyDown);
   264→  }, [editor]);
   265→
   266→  // Cmd+H — open / close find & replace bar
   267→  useEffect(() => {
   268→    function onKeyDown(e: KeyboardEvent) {
   269→      if (!(e.metaKey || e.ctrlKey) || e.key?.toLowerCase() !== "h") return;
   270→      if (!editor?.isFocused && !showFindReplace) return;
   271→      e.preventDefault();
   272→      setShowFindReplace((v) => {
   273→        if (v) editor?.chain().focus().run();
   274→        return !v;
   275→      });
   276→    }
   277→    window.addEventListener("keydown", onKeyDown);
   278→    return () => window.removeEventListener("keydown", onKeyDown);
   279→  }, [editor, showFindReplace]);
   280→
   281→  // Insert / Format menu commands forwarded from the native menu bar
   282→  useEffect(() => {
   283→    let mounted = true;
   284→    let unlisten: (() => void) | undefined;
   285→    listen<string>("menu-action", (event) => {
   286→      if (!editor || linkDialog) return;
   287→      switch (event.payload) {
   288→        case "format-bold":
   289→          editor.chain().focus().toggleBold().run();
   290→          break;
   291→        case "format-italic":
   292→          editor.chain().focus().toggleItalic().run();
   293→          break;
   294→        case "format-strike":
   295→          editor.chain().focus().toggleStrike().run();
   296→          break;
   297→        case "format-code":
   298→          editor.chain().focus().toggleCode().run();
   299→          break;
   300→        case "format-heading-1":
   301→          editor.chain().focus().toggleHeading({ level: 1 }).run();
   302→          break;
   303→        case "format-heading-2":
   304→          editor.chain().focus().toggleHeading({ level: 2 }).run();
   305→          break;
   306→        case "format-heading-3":
   307→          editor.chain().focus().toggleHeading({ level: 3 }).run();
   308→          break;
   309→        case "format-blockquote":
   310→          editor.chain().focus().toggleBlockquote().run();
   311→          break;
   312→        case "format-bullet-list":
   313→          editor.chain().focus().toggleBulletList().run();
   314→          break;
   315→        case "format-ordered-list":
   316→          editor.chain().focus().toggleOrderedList().run();
   317→          break;
   318→        case "insert-link": {
   319→          const href = editor.getAttributes("link").href ?? "";
   320→          setLinkDialog({ href });
   321→          break;
   322→        }
   323→        case "insert-code-block":
   324→          editor.chain().focus().toggleCodeBlock().run();
   325→          break;
   326→        case "insert-hr":
   327→          editor.chain().focus().setHorizontalRule().run();
   328→          break;
   329→        case "insert-table":
   330→          editor.chain().focus().insertTable({ rows: 3, cols: 3, withHeaderRow: true }).run();
   331→          break;
   332→      }
   333→    }).then((fn) => {
   334→      if (mounted) {
   335→        unlisten = fn;
   336→      } else {
   337→        fn();
   338→      }
   339→    });
   340→    return () => {
   341→      mounted = false;
   342→      unlisten?.();
   343→    };
   344→  }, [editor, linkDialog]);
   345→
   346→  return (
   347→    <div className="editor-wrapper">
   348→      <div ref={scrollRef} className="editor-scroll">
   349→        <EditorContent editor={editor} />
   350→      </div>
   351→      {editor && showFindReplace && (
   352→        <FindReplaceBar
   353→          editor={editor}
   354→          onClose={() => {
   355→            setShowFindReplace(false);
   356→            editor.chain().focus().run();
   357→          }}
   358→        />
   359→      )}
   360→      {editor && <TableControls editor={editor} />}
   361→      {editor && (
   362→        <BubbleMenu
   363→          editor={editor}
   364→          onLinkClick={() => {
   365→            const href = editor.getAttributes("link").href ?? "";
   366→            setLinkDialog({ href });
   367→          }}
   368→        />
   369→      )}
   370→      {linkDialog && (
   371→        <LinkDialog
   372→          initialHref={linkDialog.href}
   373→          onApply={(url) => {
   374→            editor?.chain().focus().extendMarkRange("link").setLink({ href: url }).run();
   375→            setLinkDialog(null);
   376→          }}
   377→          onRemove={() => {
   378→            editor?.chain().focus().extendMarkRange("link").unsetLink().run();
   379→            setLinkDialog(null);
   380→          }}
   381→          onCancel={() => setLinkDialog(null)}
   382→        />
   383→      )}
   384→    </div>
   385→  );
   386→}
   387→

