/* ── Image node ─────────────────────────────────────────────────────────── */

.image-node-wrapper {
  display: inline-block;
  position: relative;
  vertical-align: top;
  max-width: 100%;
}

.image-node-wrapper img {
  display: block;
  max-width: 100%;
  border-radius: 4px;
  transition: outline 0.1s;
}

.image-selected img {
  outline: 2px solid var(--color-accent);
  outline-offset: 2px;
}

.image-edit-bar {
  position: absolute;
  top: calc(100% + 6px);
  left: 0;
  min-width: 280px;
  background: var(--color-surface-subtle);
  border: 1px solid var(--color-border-strong);
  border-radius: 6px;
  padding: 8px 10px;
  display: flex;
  flex-direction: column;
  gap: 6px;
  z-index: 20;
  box-shadow: 0 4px 12px var(--shadow-tooltip);
}

.image-edit-field {
  display: flex;
  align-items: center;
  gap: 8px;
}

.image-edit-label {
  font-size: 10px;
  font-weight: 600;
  color: var(--color-fg-subtle);
  text-transform: uppercase;
  letter-spacing: 0.07em;
  width: 22px;
  flex-shrink: 0;
}

.image-edit-input {
  flex: 1;
  height: 26px;
  padding: 0 6px;
  font-size: 12px;
  font-family: var(--font-mono, monospace);
  color: var(--color-fg);
  background: var(--color-surface);
  border: 1px solid var(--color-border-strong);
  border-radius: 4px;
  outline: none;
  box-sizing: border-box;
  transition: border-color 0.15s;
}

.image-edit-input:focus {
  border-color: var(--color-accent);
}

