/* Tiptap / ProseMirror editor styles */

.editor-wrapper {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  background: var(--color-surface);
}

.editor-scroll {
  flex: 1;
  overflow-y: auto;
  padding: 48px 0;
}

.ProseMirror {
  max-width: 680px;
  margin: 0 auto;
  padding: 0 24px;
  font-family: var(--font-editor);
  font-size: var(--font-editor-size, 17px);
  line-height: 1.75;
  color: var(--color-fg);
  outline: none;
  min-height: 100%;
}

/* Headings */
.ProseMirror h1 {
  font-size: 2em;
  font-weight: 700;
  line-height: 1.25;
  margin-top: 1.5em;
  margin-bottom: 0.5em;
  color: var(--color-fg);
}

.ProseMirror h2 {
  font-size: 1.5em;
  font-weight: 600;
  line-height: 1.3;
  margin-top: 1.4em;
  margin-bottom: 0.4em;
}

.ProseMirror h3 {
  font-size: 1.2em;
  font-weight: 600;
  line-height: 1.35;
  margin-top: 1.3em;
  margin-bottom: 0.35em;
}

/* First heading at top — no extra top margin */
.ProseMirror > h1:first-child,
.ProseMirror > h2:first-child,
.ProseMirror > h3:first-child {
  margin-top: 0;
}

/* Paragraphs */
.ProseMirror p {
  margin-bottom: 1em;
}

.ProseMirror p:last-child {
  margin-bottom: 0;
}

/* Bold & Italic */
.ProseMirror strong {
  font-weight: 700;
}

.ProseMirror em {
  font-style: italic;
}

/* Inline code */
.ProseMirror code {
  font-family: var(--font-mono);
  font-size: 0.875em;
  background: var(--color-surface-active);
  border: 1px solid var(--color-border);
  border-radius: 3px;
  padding: 0.1em 0.35em;
}

/* Code block */
.ProseMirror pre {
  font-family: var(--font-mono);
  font-size: 0.875em;
  background: var(--color-surface-subtle);
  border: 1px solid var(--color-border);
  border-radius: 6px;
  padding: 16px 20px;
  overflow-x: auto;
  margin: 1.2em 0;
  line-height: 1.6;
}

.ProseMirror pre code {
  background: none;
  border: none;
  padding: 0;
  font-size: 1em;
}

/* Code block with language bar — reset pre so bar and block form one unified unit */
.ProseMirror .code-block-wrapper pre {
  margin: 0;
  border-top: none;
  border-top-left-radius: 0;
  border-top-right-radius: 0;
  padding-top: 12px;
}

/* Blockquote */
.ProseMirror blockquote {
  border-left: 3px solid var(--color-accent);
  padding-left: 1em;
  margin: 1.2em 0;
  color: var(--color-fg-muted);
  font-style: italic;
}

/* Lists */
.ProseMirror ul,
.ProseMirror ol {
  padding-left: 1.5em;
  margin: 0.75em 0;
}

.ProseMirror li {
  margin-bottom: 0.25em;
}

/* Horizontal rule */
.ProseMirror hr {
  border: none;
  border-top: 1px solid var(--color-border);
  margin: 2em 0;
}

/* Links */
.ProseMirror a {
  color: var(--color-accent);
  text-decoration: underline;
  text-underline-offset: 2px;
}

/* Images */
.ProseMirror img {
  max-width: 100%;
  border-radius: 6px;
  margin: 1em 0;
}

/* Placeholder */
.ProseMirror p.is-editor-empty:first-child::before {
  content: attr(data-placeholder);
  color: var(--color-fg-subtle);
  pointer-events: none;
  float: left;
  height: 0;
  font-family: var(--font-ui);
  font-style: normal;
}

/* Selection */
.ProseMirror ::selection {
  background: var(--color-accent-subtle);
}

/* Focus ring — hidden, we style it via the wrapper */
.ProseMirror:focus {
  outline: none;
}

/* ── Syntax highlighting (lowlight/highlight.js tokens) ─── */
.hljs-comment,
.hljs-quote {
  color: var(--color-syntax-comment);
  font-style: italic;
}

.hljs-keyword,
.hljs-selector-tag,
.hljs-built_in,
.hljs-name,
.hljs-tag {
  color: var(--color-syntax-keyword);
}

.hljs-string,
.hljs-title,
.hljs-section,
.hljs-attribute,
.hljs-literal,
.hljs-template-tag,
.hljs-template-variable,
.hljs-type,
.hljs-addition {
  color: var(--color-syntax-string);
}

.hljs-deletion,
.hljs-selector-attr,
.hljs-selector-pseudo,
.hljs-meta {
  color: var(--color-syntax-meta);
}

.hljs-doctag,
.hljs-attr {
  color: var(--color-syntax-attr);
}

.hljs-symbol,
.hljs-bullet,
.hljs-link,
.hljs-subst,
.hljs-variable,
.hljs-number,
.hljs-regexp {
  color: var(--color-syntax-number);
}

.hljs-emphasis {
  font-style: italic;
}

.hljs-strong {
  font-weight: bold;
}

/* ── Typora-style inline syntax reveal ─────────── */
.inline-syntax {
  font-family: var(--font-mono);
  font-size: 0.8em;
  user-select: none;
  pointer-events: none;
  opacity: 0.55;
  letter-spacing: 0;
}

.inline-syntax-link {
  color: var(--color-accent);
  opacity: 0.75;
}

/* URL hint is clickable — override pointer-events for this part only */
.link-url-hint {
  pointer-events: auto;
  cursor: pointer;
  opacity: 0.65;
  border-radius: 2px;
  transition: opacity 0.12s;
}

.link-url-hint:hover {
  opacity: 1;
  text-decoration: underline;
  text-underline-offset: 2px;
}

/* ── Math / LaTeX (KaTeX) ──────────────────────── */
.tiptap-mathematics-render {
  cursor: pointer;
  border-radius: 3px;
  transition: background 0.12s;
}

.tiptap-mathematics-render:hover {
  background: var(--color-surface-hover);
}

/* Editable state: show raw LaTeX in a styled input */
.tiptap-mathematics-render--editable {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  background: var(--color-surface-subtle);
  border: 1px solid var(--color-accent);
  border-radius: 4px;
  padding: 2px 6px;
  font-family: var(--font-mono);
  font-size: 0.85em;
  color: var(--color-fg);
}

/* Block math wrapper */
.ProseMirror [data-type="block-math"] {
  margin: 1.2em 0;
  text-align: center;
}

.ProseMirror [data-type="block-math"] .tiptap-mathematics-render {
  display: block;
  padding: 12px;
  background: var(--color-surface-subtle);
  border-radius: 6px;
  overflow-x: auto;
}

/* Error indicator */
.inline-math-error,
.block-math-error {
  color: var(--color-error);
  background: color-mix(in srgb, var(--color-error) 10%, transparent);
  border-radius: 3px;
  padding: 0 3px;
}

/* ── Text folding ──────────────────────────────── */
.ProseMirror .foldable {
  position: relative;
}

.fold-chevron {
  position: absolute;
  left: -22px;
  top: 50%;
  transform: translateY(-50%);
  width: 16px;
  height: 16px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 9px;
  color: var(--color-fg-subtle);
  cursor: pointer;
  user-select: none;
  border-radius: 3px;
  transition:
    color 0.12s,
    background 0.12s;
}

.fold-chevron::before {
  content: "▼";
}

.fold-chevron:hover {
  color: var(--color-fg);
  background: var(--color-surface-hover);
}

/* When heading has fold-closed class, chevron points right */
.ProseMirror .fold-closed .fold-chevron::before {
  content: "▶";
}

/* ── Tables ────────────────────────────────────── */
.ProseMirror .tableWrapper {
  overflow-x: auto;
  margin: 1.2em 0;
}

.ProseMirror table {
  border-collapse: collapse;
  width: 100%;
  font-size: 0.9em;
}

.ProseMirror th,
.ProseMirror td {
  border: 1px solid var(--color-border);
  padding: 6px 12px;
  text-align: left;
  vertical-align: top;
  min-width: 80px;
  position: relative;
}

.ProseMirror th {
  background: var(--color-surface-subtle);
  font-weight: 600;
  color: var(--color-fg);
}

.ProseMirror td {
  background: var(--color-surface);
}

.ProseMirror .selectedCell::after {
  content: "";
  position: absolute;
  inset: 0;
  background: var(--color-accent-subtle);
  pointer-events: none;
  z-index: 1;
}

/* Column resize handle */
.ProseMirror .column-resize-handle {
  position: absolute;
  right: -2px;
  top: 0;
  bottom: 0;
  width: 4px;
  background: var(--color-accent);
  cursor: col-resize;
  z-index: 20;
}

/* Link preview tooltip */
.link-preview-tooltip {
  position: fixed;
  z-index: 1000;
  display: none;
  max-width: 360px;
  background: var(--color-surface-subtle);
