     1→import Image from "@tiptap/extension-image";
     2→import type { NodeViewProps } from "@tiptap/react";
     3→import { NodeViewWrapper, ReactNodeViewRenderer } from "@tiptap/react";
     4→import { useEffect, useRef, useState } from "react";
     5→import { resolveImageSrc } from "../imageUtils";
     6→
     7→export { resolveImageSrc };
     8→
     9→export interface ImageRendererOptions {
    10→  filePath?: string;
    11→  assetRoot?: string;
    12→  cdnBase?: string;
    13→  inline?: boolean;
    14→  allowBase64?: boolean;
    15→  HTMLAttributes?: Record<string, unknown>;
    16→}
    17→
    18→function ImageNodeView({ node, extension, selected, updateAttributes }: NodeViewProps) {
    19→  const { filePath, assetRoot, cdnBase } = extension.options as ImageRendererOptions;
    20→  const { src, alt } = node.attrs as { src: string; alt?: string };
    21→
    22→  const [srcInput, setSrcInput] = useState(src);
    23→  const [altInput, setAltInput] = useState(alt ?? "");
    24→
    25→  // Keep refs so onBlur always reads the latest value regardless of render timing
    26→  const srcRef = useRef(srcInput);
    27→  const altRef = useRef(altInput);
    28→
    29→  const updateSrc = (v: string) => {
    30→    setSrcInput(v);
    31→    srcRef.current = v;
    32→  };
    33→  const updateAlt = (v: string) => {
    34→    setAltInput(v);
    35→    altRef.current = v;
    36→  };
    37→
    38→  // Sync from node attrs when not editing (undo/redo, external updates)
    39→  useEffect(() => {
    40→    if (!selected) {
    41→      setSrcInput(src);
    42→      srcRef.current = src;
    43→    }
    44→  }, [src, selected]);
    45→  useEffect(() => {
    46→    if (!selected) {
    47→      setAltInput(alt ?? "");
    48→      altRef.current = alt ?? "";
    49→    }
    50→  }, [alt, selected]);
    51→
    52→  const resolvedSrc = resolveImageSrc(srcInput, filePath, assetRoot, cdnBase);
    53→
    54→  return (
    55→    <NodeViewWrapper
    56→      as="span"
    57→      contentEditable={false}
    58→      className={`image-node-wrapper${selected ? " image-selected" : ""}`}
    59→    >
    60→      <img src={resolvedSrc} alt={altInput} />
    61→      {selected && (
    62→        <div className="image-edit-bar">
    63→          <div className="image-edit-field">
    64→            <span className="image-edit-label">src</span>
    65→            <input
    66→              className="image-edit-input"
    67→              value={srcInput}
    68→              onChange={(e) => updateSrc(e.target.value)}
    69→              onBlur={() => updateAttributes({ src: srcRef.current })}
    70→              onKeyDown={(e) => {
    71→                e.stopPropagation();
    72→                if (e.key === "Enter") {
    73→                  updateAttributes({ src: srcRef.current });
    74→                  e.currentTarget.blur();
    75→                }
