        assert_eq!(strip_quote_pair("\"cdnBase:", "cdnBase", '"'), None);
    }

    // ── parse_cdn_base ───────────────────────────────────────────────────────

    fn write_config(dir: &TempDir, content: &str) -> PathBuf {
